INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_122$$, 2027, $$LAND FORCES SYSTEMS READINESS - Supports the Army National Guard Long Haul Communications program. Provides resources to the 50 States, three Territories,
and the District of Columbia's Joint Force Headquarters and supports homeland defense initiatives for long-haul command and control communications, which includes
communications facilities, engineering, and installations. Resources support the Defense Communications Systems, the Defense Switched Network, Non-classified
Internet Protocol Router Network, Secret Internet Protocol Router Network, network services and dedicated voice and data circuits.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 131, 132, $$21f09b9b49bbe07efd3b49524fd44d93db560550a8b8954ceb8ed51c8f6a60cc$$, $$2026-05-09T20:59:14.85782+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_432$$, 2027, $$SERVICEWIDE COMMUNICATIONS - Provides funding for Automation and Information Systems which includes Information Services, Communication Systems Support,
Defense Satellite Communications System, Connect the Logistician, General Fund Enterprise Business System, Biometrics Enterprise, Human Resources Accessioning
systems, Integrated Personnel and Pay System-Army, and Enterprise License Agreements.

Automation and Information Systems - Provides funding for Reserve Component Automation System (RCAS) legacy applications that focuses on career management,
civilian manpower data, human capital capabilities, and training and readiness. Legacy systems are slated for subsumption by Army Enterprise Applications through FY
2026.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 229, 230, $$7c244a87ab3d16745711d7d2e36ca7cb21a511ff5aec50a0f64a2792be7779ac$$, $$2026-05-09T20:59:14.85782+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_421$$, 2027, $$SECOND DESTINATION TRANSPORTATION (SDT) OPERATIONS - Second Destination Transportation supports re-stationing units to right size the States and optimize
readiness. Funds Army National Guard (ARNG) for redistribution of major end items and divestiture turn-in directed by the ARNG to a Depot. Funds lateral transfer of
equipment between and across ARNG units/commands to maximize equipment on-hand levels and increase readiness. Priorities of effort include: (1) equipment that
cascades in support of the Regionally Aligned Readiness and Modernization Model; (2) equipment inducted into the Depot Overhaul program, repair and return program;
(3) ARNG Directed Lateral Transfers; and (4) equipment directed for displacement by the ARNG to a Depot.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 209, 210, $$b9eb6958edde62e1bcbf63374faeb8229b2126f5b10f58a96973e520db696c56$$, $$2026-05-09T20:59:14.85782+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_caaf_umbrella$$, 2027, $$The United States Court of Appeals for the Armed Forces (USCAAF) funding provides all customary expenses required to operate the activity such as salaries,
benefits, travel expenses, rent, communications services, equipment purchases, contractual information technology support, security services, and the expense of
printing opinions and decisions of the USCAAF. The requested funds typically support five civilian judges, appointed for 15-year terms, and a staff of 54 civilian
personnel. The Court is an Article I Court established by Chapter 47 of Title 10, United States Code (also known as the Uniform Code of Military Justice (UCMJ)),
specifically Section 941. The Court exercises appellate jurisdiction over cases arising under the UCMJ on a broad range of legal issues. Decisions by the Court
are subject to direct review by the Supreme Court of the United States.$$, NULL, NULL, $$O&M/FY27/DW/Vol1_Part2/CAAF_OP-5.pdf$$, 5, 6, $$064f603beb3d4bfc5d510d0d443f72ba7e350da2884f8950e46472849e123c95$$, $$2026-05-09T20:59:14.85782+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_4a4g$$, 2027, $$Headquarters, Marine Corps (HQMC) consists of the Commandant of the Marine Corps and those staff agencies that assist and support him in the discharge of his lawfully
prescribed responsibilities, pursuant to Title 10 USC. The Commandant is the principal advisor to the Secretary of the Navy on Marine Corps matters, which include but are not
limited to administration, policy development, plans and programs, audit, prioritizing requirements, training, discipline, internal organization, resource management, efficiency,
operations, and the overall readiness of the force.

Costs financed include HQMC civilian salaries and benefits, automated data processing, printing and reproduction, personnel travel expenses, civilian training, equipment
purchases and maintenance, communications, Defense Finance and Accounting Service, the Marine Corps Embassy Security Group, and Pentagon Reservation.$$, NULL, NULL, $$O&M/FY27/Navy/OMMC_Book.pdf$$, 168, 176, $$b0d84a2ee3687b8faf37923c4b3ff062b17dbe6c20c612491f369195ab684733$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_reserve_1a9a$$, 2027, $$The Aviation Logistics program provides Navy Reserve and Marine Corps Reserve aviation programs a budget line item for Contractor Logistics Support (CLS) and
Performance-Based Logistics (PBL) contracts. CLS is the performance of maintenance and/or materiel management functions for a DoW system by a commercial activity. PBL is
the purchase of support as an integrated, performance package designed to optimize system readiness and meet performance goals for a weapon system through long-term support
arrangements with clear lines of authority and responsibility. The MV-22 power-by-the-hour (PBtH) contractor provides engine sustainment on a flight-hour basis that includes all
material required for depot engine and component repair. The KC-130J PBtH contractor provides all the parts support required in the performance of depot-level maintenance
both scheduled and unscheduled for the engine and propeller systems.$$, NULL, NULL, $$O&M/FY27/Navy/OMNR_Book.pdf$$, 45, 51, $$d84d4d04e4c55f3c5a6577d41940ad1e4b40999bd543cd783f4ce27a06fb20a5$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_reserve_4a1m$$, 2027, $$This sub-activity group provides resources for the operation of the Office of the Chief of Navy Reserve. The Chief of Navy Reserve provides policy, control,
administration, and direction including the management of all resources (manpower, hardware, and facilities) to facilitate an optimum training posture and
mobilization readiness. To aid in readiness, funding supports Navy Recruiting Reserve Command (NRRC) and five Reserve Talent Acquisition Groups (RTAGs)
commands to fully exercise Navy Reserve recruiting capabilities. The positions allow for a more expansive deployment of RTAGs, intensifying efforts in key
regions, capitalizing on emerging opportunities, and bolstering responsiveness to dynamic shifts in the recruitment landscape. This aligns with the commitment to
securing a diverse and highly qualified Reserve Force. Funding also provides for Defense Finance and Accounting Services (DFAS) for the Navy Reserve.$$, NULL, NULL, $$O&M/FY27/Navy/OMNR_Book.pdf$$, 100, 106, $$3d16276b666fec214110bbbd408fa9c2ad349963ae1fa0d115ee780117afe37a$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_3c2f$$, 2027, $$This subactivity funds the Marine Corps' off-duty and voluntary education program which provides Marines an opportunity to enhance their careers through education programs by
providing tuition assistance support. Levels of education financed in this program are apprenticeship, vocational/technical, and college level undergraduate and graduate courses –
which provide training opportunities for Marines to improve performance and enhance professional military education. The program improves recruitment and retention (higher
education levels correlate to higher reenlistment rates) and enhances readiness (reduces disciplinary problems, increase prospects for promotion, increases Armed Services
Vocational Aptitude Battery (ASVAB) scores, and supports career progression).

MANDATORY FUNDING JUSTIFICATION:

The FY 2026 spend plan amount for Off-Duty and Voluntary Education includes $27,850 thousand discretionary and $15,000 thousand of mandatory
(reconciliation) for a total of $42,850 thousand.$$, NULL, NULL, $$O&M/FY27/Navy/OMMC_Book.pdf$$, 147, 153, $$81f811769120130f6fa9449eaa27b874a1145df52708a642ce88a5c89fca5727$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_3a1c$$, 2027, $$The transition from civilian life to duties as a Marine occurs as a result of recruit training for new enlistees conducted at one of the two Marine Corps Recruit Depots (MCRD)
located at San Diego, California and at Parris Island, South Carolina. This intense period of training is designed to prepare the new Marine for assignment to units of the Fleet
Marine Force, to major posts and stations, to duty at sea aboard vessels of the U.S. Navy, and to specialized skill training prior to assignment to a unit. During recruit training, the
Marine is taught basic military skills, and develops confidence in themselves and in members of their unit, while being closely supervised by special skilled Marines. The
objective of the training is to produce a Marine who can assimilate well into a unit, and in time of emergency, sustain themselves on the battlefield. Marines graduating from
recruit training are assigned to formal schools for specialized skills training in a military occupational specialty.$$, NULL, NULL, $$O&M/FY27/Navy/OMMC_Book.pdf$$, 99, 105, $$4f871f135856fb01cfcfbc0198ef7432e891ac8e50f6a74da68c08d466fa0e42$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_dcma_cyber$$, 2026, $$The Defense Contract Management Agency (DCMA) Cybersecurity Program mission is to execute the Department of Defense (DoD) Cyber
Strategy while achieving the cyberspace objectives to protect the warfighter. To protect, secure, and defend the DCMA information and
Information Technology (IT) systems, the DCMA IT must maintain a vigilant presence to detect and deter threats and vulnerabilities in cyberspace,
expand alliances and partnerships, improve infrastructures and firewalls, and cultivate and sustain a cyber-readiness environment and
workforce. The DCMA DIB Cyber Assessment Center, is DoD's sole entity for DIB-wide cyber assessments, conducting over 700 assessments on
$2.8 trillion in contracts, proactively identifying and mitigating vulnerabilities within the defense industrial base.

The DCMA Cyber budget protects, secures, and defends information and IT systems under its purview to ensure functional owners and operators
have confidence in the confidentiality, integrity, availability, and non-repudiation of the DCMA information needed to make informed decisions.
Some key security principles include isolation; containment; redundancy; layers of defense; least privilege; situational awareness; and physical or
logical segmentation of networks, services, and applications. This budget supports these activities by providing government and contractor support
to prevent unauthorized network access by protecting all information systems, enclaves, and computing environments from external and internal
threats of interception, modification, fabrication, and interruption.

In FY 2026, the DCMA plans to continue to make incremental improvements to the cybersecurity operational environment by enhancing core
processes and investments towards the defense of the DCMA and DoD enterprise. In addition to reaffirming the Agency's current security posture
through validation and verification of security controls, DCMA will continue to work towards implementing of the Zero Trust Reference Architecture
(ZTRA), supporting the strategic outcomes of ZTRA outlined in the current DoD ZT Strategy. The DCMA will continue to leverage DISA
Cybersecurity Service Provider (Tier II/III) services to increase visibility and Area of Operations (AO), streamlining the Cybersecurity Service
Provider (CSSP) efforts within the DCMA, while simultaneously strengthening the capability to perform and execute required mission partner
CSSP capabilities at the Tier III level. The DCMA anticipates these efforts will support the protection and defense of information and information
systems facilitating a transformative evolution into a more agile, mobile, and cloud-supported workforce.

The DCMA Cybersecurity Center requires a specialized highly skilled, qualified cybersecurity workforce, including civilians and contractors, to
perform defensive cyberspace operations (DCO). This function directly supports improving of cybersecurity operations, supporting effective
damage containment, mitigation, and remediation activities when a device, network, user, or credential becomes compromised.

                                                                                                                                    DCMA - Cyber

                                                 Defense Contract Management Agency - Cyber$$, $$$$, NULL, $$O&M/FY26/DW/OM_Volume1_Part1.pdf$$, 228, 231, $$f94490cc4a9a06c965b716a9d6c0023c4baeae08c95f3074d8dd9969ddf28390$$, $$2026-05-09T21:12:37.492901+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_reserve_4emm$$, 2027, NULL, NULL, NULL, $$O&M/FY27/Navy/OMMCR_Book.pdf$$, NULL, NULL, $$361c1773645a550366c4bfaa9e433b8dc97832c1e70c6d76e5b3fd139c1c9137$$, $$2026-05-09T20:59:14.85782+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_111$$, 2027, $$MANEUVER UNITS - Supports the training, operations, and civilian manpower required to maintain readiness in the Army National Guard's (ARNG) Brigade Combat
Teams (BCTs), Division Headquarters, and associated maneuver forces while leveraging live, virtual, and constructive capabilities to conduct training focused on
Multidomain Operations capabilities.

Home Station Training - Resources Modification Table of Organizational Equipment (MTOE) units to conduct collective training. This includes maintenance repair parts
and petroleum, oil, lubricants, Soldier Support per capita costs, Army National Guard (ARNG) Combat Training Center (CTC) and Combat Readiness Exercises (CRX),
command funded contracts to sustain routine day-to-day operations, and other activities directed by Army and Army National Guard leadership. These resources directly
support each commander's ability to improve unit training and readiness. Includes funding for operations of Heavy, Light, and Stryker Brigade Combat Teams and
associated organic forces.

MANDATORY FUNDING JUSTIFICATION:

The FY 2026 spend plan amount for Maneuver Units includes $858,599 thousand of discretionary and $43,790 thousand of mandatory for a total of $902,569 thousand.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 42, 43, $$5f6fb19cb61b0f412863dbeba86bb0c86f11e9c3cae1554e2382443e277bb17e$$, $$2026-05-09T20:59:14.85782+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_151$$, 2027, $$CYBER ACTIVITIES - CYBERSPACE OPERATIONS - Resources the manning, training and equipping of Army National Guard (ARMG) organizations responsible for
cyberspace operations support. Supports ARNG cyberspace forces capable of conducting full-spectrum cyberspace operations both on and off Department of War
Information Network (DOWIN) within the parameters of federal and state authorities. The units resourced include the 91st Cyber Brigade spanning 31 States, Cyber
Protection Team Mission Elements (CPT-MEs) spanning 38 States, and 54 Defensive Cyber Operations Elements (DCOEs), located at the State/Territory's Joint Force
Headquarters (JFHQ).

Force Readiness Operations Support - Cyber - Funds cyberspace training and equipment to achieve a fully mission-capable and ready operational force, improving
overall ARNG cyber defensive posture and unit readiness. Provides resources for individual training courses to meet Duty Military Occupation Specialty Qualifications
(DMOSQ), Department of War Directive (DoWD) 8140, US Cyber Command's Cyber Mission Forces (USCYBERCOM CMF), Work Role Training requirements, and
participation and preparation for annual various collective cyber training events such as Cyber Shield, Cyber Fortress, Cyber Yankee, and many others.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 189, 190, $$c2dfeb4b472ec959a8f32d3f3ddba7624d4f07fc91111078ce8b13ab2d9e2db7$$, $$2026-05-09T20:59:14.85782+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_reserve_bsmr$$, 2027, $$Facility sustainment, restoration and modernization (FSRM) includes funding for shore activities supporting ship, aviation, combat operations and operational support forces.
FSRM funding enables maintenance, repair and minor construction for all buildings, structures, ground and utility systems to permit assigned forces and tenants to perform their
mission. This program has two major work classifications and subprograms: the sustainment program and the restoration and modernization program. These programs
accomplish work through a combination of recurring maintenance contracts, contracted special projects and government forces. Facility sustainment includes regularly scheduled
maintenance, emergency services and cyclical major repairs to preserve shore infrastructure in working order over its expected service life. Restoration and modernization
includes repairs to restore facilities degraded by inadequate sustainment, excessive age or other damage. It also funds modifications required to support currently assigned
missions and implement new or higher facility standards.$$, NULL, NULL, $$O&M/FY27/Navy/OMNR_Book.pdf$$, 84, 90, $$95809dcc807e31ae47745cd7984f2d65ecfa34c4affb05581a226edfedb7b043$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_bss1$$, 2027, $$Base Operating Support (BOS) for Navy installations enables sea, air and land operations for the Navy's fleet forces. Support functions include port and airfield operations, utilities
management and energy security, supply logistics, fleet ground transportation, environmental planning and compliance, security, fire and emergency services, personnel support,
unaccompanied housing, temporary lodging, facilities planning and contract award/management, custodial services, grounds maintenance, child care, galley functions, information
technology, training, safety programs, and morale, welfare and recreation.

MANDATORY FUNDING JUSTIFICATION:

The FY 2027 request for Base Operating Support includes $6,069,456 thousand of discretionary and $0 thousand of mandatory (reconciliation) for a total of $6,069,456 thousand.

The FY 2026 spend plan amount for Base Operating Support includes $5,991,924 thousand of discretionary and $165,024 thousand of mandatory (reconciliation) for a
total of $6,156,948 thousand. The mandatory funds for Base Operating Support supports child and youth programs, and activities for border operations and counter-narcotics.$$, NULL, NULL, $$O&M/FY27/Navy/OMN_Book.pdf$$, 375, 387, $$352a0d43215f6cc1a2811993c71c68576d2d76a7a0bfade94fd8607297dbfc8e$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_4epj$$, 2026, $$Sub-program of 4A1M (Administration). FY2026 estimate: $0. This sub-activity group (4EPJ, Judgement Fund) appears as a line item within the parent SAG's O-1 Summary table — see OMN_Book.pdf line 880: "1804N   760    4EPJ Judgement Fund                            U         3,709". Per the parent SAG's OP-5 narrative, sub-program rollups of this kind do not receive standalone descriptions; refer to the parent SAG (4A1M) narrative for context. Source: O&M/FY26/Navy/OMN_Book.pdf line 880 (line-item citation) + parent SAG 4A1M narrative. synth_subprogram v41.$$, NULL, NULL, $$O&M/FY26/Navy/OMN_Book.pdf$$, 880, 880, $$356ae45a0d71c55e626dd11e212dbf31a48d2fe4ff59ae18e9012ed776347397$$, $$2026-05-10T01:03:08.635372+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_4cdp$$, 2027, $$This sub-activity group provides funding to support Security Programs. Force Structure: Details are held at a higher classification. (Source: FY27 PB OMN_Book, Exhibit OP-5 4CDP, pp. 695-701.)$$, NULL, NULL, $$O&M/FY27/Navy/OMN_Book.pdf$$, 695, 696, $$v54_4cdp_fy27_op5$$, $$2026-05-10T21:47:21.79115+00:00$$) ON CONFLICT DO NOTHING;
