INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_4a7g$$, 2027, $$This sub-activity group provides funding to support Security Programs (Marine Corps). Force Structure: Details are held at a higher classification. (Source: FY27 PB OMMC_Book, Exhibit OP-5 4A7G, pp. 177-183.)$$, NULL, NULL, $$O&M/FY27/Navy/OMMC_Book.pdf$$, 177, 178, $$v54_4a7g_fy27_op5$$, $$2026-05-10T21:47:21.79115+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_reserve_1a3a$$, 2027, $$This sub-activity group finances the depot maintenance (major repair/rebuild) of Marine Forces Reserve ground equipment. Depot Maintenance programs fund the overhaul,
repair, and maintenance of automotive equipment, combat vehicles, construction equipment, electronics and communications systems, general purpose equipment, missiles, and
ordnance/weapons/munitions performed at both public Department of War (DoW) and private (contractor) facilities. Repair and rebuild are accomplished on a coordinated
schedule to help manage and maintain the materiel readiness of the equipment inventory necessary to support the operational needs of the Marine Corps. Items programmed for
repair are screened to ensure that a valid stock requirement exists and that the repair or rebuild of the equipment is the most cost-effective means of satisfying the requirement.
This program is closely coordinated with the Procurement, Marine Corps appropriation to ensure that the combined repair and procurement program provides a balanced level of
attainment and maintenance of inventory objectives for major equipment. The specified items are updated annually based on current applicable cost factors at the performing
activities.$$, NULL, NULL, $$O&M/FY27/Navy/OMMCR_Book.pdf$$, 27, 33, $$5fbf887f651ca3e1526fdcd6a27642671afeb271a1f819aa0db9a2b2f962b82c$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_153$$, 2027, $$CYBER ACTIVITIES - CYBERSECURITY - Funds the 50 States, three Territories, and the District of Columbia's Joint Force Headquarters Network Enterprise Center
(NEC) programs to support a range of security initiatives, including computer network security policy analysis and Cybersecurity education and training. Additionally,
Cybersecurity funds measures that protect and defend information and information systems by ensuring their availability and confidentiality to achieve a Defense-In-Depth
approach that integrates the capabilities of personnel, operations, and technology.

Cybersecurity - Funds Department of War mandated Cyber Workforce training and certification programs, Enterprise continuous monitoring, Contract Management
equivalent (CME) support for commands to manage cybersecurity programs supporting the Department of War Information Network (DOWIN-A), and Senior Leader
defined enterprise cybersecurity initiatives.

Cybersecurity Activities - Resources the implementation of necessary hardware and software system improvements, long-term monitoring, protection, and sustainment
of cybersecurity control systems for defense infrastructure. Funds initial control systems inventory and cyber security vulnerability assessments to mitigate cybersecurity
risks for all facility control systems across the ARNG enterprise.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 199, 200, $$db968d5065f2e233813b6053ca3b5764868d32b3bf38f760bfb4db70e1e80e5c$$, $$2026-05-09T20:59:14.85782+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_4a2w$$, 2026, $$Sub-program of 4B2E (Environmental Programs). FY2026 estimate: $0. This sub-activity group (4A2W, Recycling) appears as a line item within the parent SAG's O-1 Summary table — see OMMC_Book.pdf line 459: "1106N   170   4A2W Recycling                               U             4,568". Per the parent SAG's OP-5 narrative, sub-program rollups of this kind do not receive standalone descriptions; refer to the parent SAG (4B2E) narrative for context. Source: O&M/FY26/Navy/OMMC_Book.pdf line 459 (line-item citation) + parent SAG 4B2E narrative. synth_subprogram v41.$$, NULL, NULL, $$O&M/FY26/Navy/OMMC_Book.pdf$$, 459, 459, $$7a5b581f805b26d2c364743ac6ae7b3f5ec20eee4747c5a16e659d4ec42eba53$$, $$2026-05-10T01:03:08.635372+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_reserve_1a1a$$, 2027, $$The Operating Forces budget line item supports the day-to-day costs to train and support the Marine Forces Reserve (MFR). Programs within this line item include funding for
materiel readiness, purchase and replacement of expense type items authorized by unit training allowances, local repair of equipment, training centers, and embarkation materials
for training and preparation for mobilization. Operating Forces provide funding for annual exercise training in preparation for deployments such as Desert Fire Exercises (CAXs),
the Weapons and Tactics Instructor Course (WTI), Mountain Warfare training (MTX), and Arctic Weather training. It also provides resources for equipment and ammunition
shipments, essential travel, contract billeting, Maintenance Contact Teams (MCT), inspections, travel, recurring services such as Reserve Health Assessments, Contractor
Engineering Technical Services (CETS), equipment calibration, Global Command & Control System (GCCS) technicians, consumables, reproduction, and equipment
replacement/replenishment.

MANDATORY FUNDING JUSTIFICATION:

The FY 2026 spend plan amount for Operating Forces, Marine Corps Reserve includes $117,987 thousand of discretionary and $10,854 thousand of mandatory (reconciliation) for
a total of $128,841 thousand.$$, NULL, NULL, $$O&M/FY27/Navy/OMMCR_Book.pdf$$, 19, 26, $$361c1773645a550366c4bfaa9e433b8dc97832c1e70c6d76e5b3fd139c1c9137$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_3a3j$$, 2027, $$The Naval Reserve Officers Training Corps (NROTC) program produces unrestricted line Navy and Marine Corps officers. It provides college instruction to highly qualified
baccalaureate degree students who, upon graduation, receive a commission in the Navy, Marine Corps, or associated reserve program. NROTC is comprised of Scholarship and
College programs. The Scholarship Program is a long-range career officer accession program for the Regular Navy and Marine Corps. The College Program provides Naval
Reserve and Marine Corps Reserve Officers for active duty. Selectees enter either a minimum of a two-year program or a maximum of a four-year program as a College Program
or Scholarship Program student and must attain a baccalaureate degree prior to commissioning. The funds requested represent the cost of educational subsidies for Scholarship
Program students and administrative expenses of the program.
Educational subsidies consist of payments for tuition, fees and books for college courses required for a baccalaureate degree. Administrative expenses include unit operating costs,
purchase of Naval Science course textbooks, course reference materials, training aids, the costs associated with operating new student indoctrination and the costs associated with
operating several summer training sites.$$, NULL, NULL, $$O&M/FY27/Navy/OMN_Book.pdf$$, 463, 469, $$c045e7429bdafc87a3edb096f3bda4ed470d2d050bab0b3359266bfc36482459$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_4a2w$$, 2027, $$Sub-program of 4B2E (Environmental Programs). FY2027 estimate: $0. This sub-activity group (4A2W, Recycling) appears as a line item within the parent SAG's O-1 Summary table — see OMMC_Book.pdf line 520: "1106N   170   4A2W Recycling                               U          8,709". Per the parent SAG's OP-5 narrative, sub-program rollups of this kind do not receive standalone descriptions; refer to the parent SAG (4B2E) narrative for context. Source: O&M/FY27/Navy/OMMC_Book.pdf line 520 (line-item citation) + parent SAG 4B2E narrative. synth_subprogram v41.$$, NULL, NULL, $$O&M/FY27/Navy/OMMC_Book.pdf$$, 520, 520, $$7ad866f659fa8dfe9116d5cd7e305934a0056c7b807e8ce6aacc897a4e9c4704$$, $$2026-05-10T01:03:08.635372+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_4epj$$, 2027, $$Sub-program of 4A1M (Administration). FY2027 estimate: $0. This sub-activity group (4EPJ, Judgement Fund) appears as a line item within the parent SAG's O-1 Summary table — see OMN_Book.pdf line 960: "1804N   760   4EPJ Judgement Fund                            U        14,708". Per the parent SAG's OP-5 narrative, sub-program rollups of this kind do not receive standalone descriptions; refer to the parent SAG (4A1M) narrative for context. Source: O&M/FY27/Navy/OMN_Book.pdf line 960 (line-item citation) + parent SAG 4A1M narrative. synth_subprogram v41.$$, NULL, NULL, $$O&M/FY27/Navy/OMN_Book.pdf$$, 960, 960, $$8b0ba098bd5afb9d75b0d7cf11dc4b48042442dca0a3c37b9c961043e84a9b45$$, $$2026-05-10T01:03:08.635372+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_1a3a$$, 2027, $$This sub-activity group finances the depot maintenance (major repair/rebuild) of active Marine Corps ground equipment. Depot Maintenance programs fund the overhaul, repair,
and maintenance of automotive equipment, combat vehicles, construction equipment, electronics and communications systems, general purpose equipment, missiles, and
ordnance/weapons/munitions performed at both public Department of War (DoW) and private (contractor) facilities. Repair and rebuild are accomplished on a coordinated
schedule to help manage and maintain the materiel readiness of the equipment inventory necessary to support the operational needs of the Marine Corps. Items programmed for
repair are screened to ensure that a valid stock requirement exists and that the repair or rebuild of the equipment is the most cost effective means of satisfying the requirement.
This program is closely coordinated with the Procurement, Marine Corps appropriation to ensure that the combined repair and procurement program provides a balanced level of
attainment and maintenance of inventory objectives for major equipment. The specified items are updated annually based on current applicable cost factors at the performing
activities.

MANDATORY FUNDING JUSTIFICATION:

The FY 2026 spend plan amount for Depot Maintenance includes $236 thousand of discretionary and $286,000 thousand of mandatory (reconciliation) for a total
of $286,236 thousand.$$, NULL, NULL, $$O&M/FY27/Navy/OMMC_Book.pdf$$, 51, 57, $$08d3390e8058f46556fda450a89c9d497b5a25e06dec9dfb06907ee94bd855dc$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_3c5l$$, 2027, $$The Navy Junior Reserve Officers' Training Corps (NJROTC) program is a congressionally sponsored youth citizenship program mandated by Public Law 88-647. NJROTC is
intended to instill the value of citizenship, service to the United States (including an introduction to service opportunities in military, national, and public service), personal
responsibility, and a sense of accomplishment in eighth grade through high school students. Eighty-Five (85%) percent of the NJROTC operation and maintenance budget
currently supports the government's share of instructor salaries. Other expenses include cadet orientation (travel), training aids, curriculum texts and educational materials, drill
rifles, and unit operating expense funding. Administrative support costs include office operating costs, travel, and per diem for eleven (11) NJROTC area managers.

Navy also maintains a Navy National Defense Cadet Corps (NNDCC) program in partnership with qualifying secondary educational institutions. The NNDCC will provide
secondary educational institutions that do not qualify for, who do not wish to host, or currently cannot be offered an NJROTC unit, an opportunity to provide a course for students
to learn the values of citizenship, service to the United States, personal responsibility and attain a sense of accomplishment. The NNDCC program is modeled on the NJROTC
program, except that it is primarily funded by host schools.$$, NULL, NULL, $$O&M/FY27/Navy/OMN_Book.pdf$$, 543, 549, $$e74033bb7910310505ef00ee69eb93806082243430f6f901176a952ac34b8d57$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_112$$, 2027, $$MODULAR SUPPORT BRIGADES - Funds the training and operations of Multi-functional Support Brigades by leveraging live, virtual, and constructive capabilities to
conduct collective training focused on Multidomain Operations capabilities. Funds Combined Arms Training Strategy collective training events aligned based on
Continuous Transformation and Directed Readiness Table requirements. The Army National Guard (ARNG) funds ground units to conduct collective training and achieve
designated training proficiency levels.

Home Station Training - Resources Modification Table of Organizational Equipment (MTOE) and selected Table of Distribution and Allowances (TDA) units to conduct
collective training. This includes maintenance repair parts and petroleum, oil, lubricants, Soldier Support per capita costs, Army National Guard (ARNG) Combat Training
Center (CTC) and Combat Readiness Exercises (CRX), command funded contracts to sustain routine day-to-day operations, and other activities directed by Army and
Army National Guard leadership. These resources directly support each commander's ability to improve unit training and readiness. Includes funding to enable capabilities
for: cannon and rocket fires, battlefield surveillance and reconnaissance, maneuver enhancement units (e.g. military police, engineer, chemical, air defense artillery, civil
affairs, and explosive ordnance disposal), as well as logistical command and control.

MANDATORY FUNDING JUSTIFICATION:

The FY 2026 spend plan amount for Modular Support Brigades includes $210,737 thousand of discretionary and $11,966 thousand of mandatory for a total of $222,703
thousand.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 55, 56, $$03e4296d486be93bc432bf9f0d66a8a44fd1b38550a68139030a02f88f148946$$, $$2026-05-09T21:03:12.072253+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_4a3g$$, 2027, $$This sub-activity group funds transportation of Marine Corps major end items, supplies and materials through the most economical mode to meet Department of War (DoW) in-
transit standards of the Uniform Materiel Movement and Issue Priority System. Second Destination Transportation (SDT) resources support the costs of ground ammunition and
equipment movements, Military Surface Deployment and Distribution Command (SDDC) annual Port Readiness and Traffic Management charges, Defense Logistics Agency
(DLA) over-ocean transportation, General Services Administration (GSA) over-ocean transportation, Marine Corps Exchange over-ocean transportation, Defense Reutilization and
Marketing Office movements, and depot maintenance rebuild and remanufacture movements. It also funds prepositioning of Marine Corps owned materiel and equipment to
forward operating bases and cooperative security locations. All resources in this program either reimburse the U.S. Transportation Command Working Capital Fund, DLA
Working Capital Fund, or pay for commercial transportation carrier services. Servicewide Transportation finances SDT shipments for regular and emergency readiness materiel
including ammunition, chemicals, medicine, subsistence, and repair parts. Servicewide Transportation also provides transportation services, predominately from Air Mobility
Command, Military Sealift Command, and the SDDC, which are DoW working capital fund transportation activities.$$, NULL, NULL, $$O&M/FY27/Navy/OMMC_Book.pdf$$, 161, 167, $$28ee50edbcc94cfe92715861b12359f80d3a528bd37f9bddfa32c5ab75f9bcac$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_reserve_bsmr$$, 2026, $$Facility sustainment, restoration and modernization (FSRM) includes funding for shore activities supporting ship, aviation, combat operations and operational support forces.
FSRM funding enables maintenance, repair and minor construction for all buildings, structures, ground and utility systems to permit assigned forces and tenants to perform their
mission. This program has two major work classifications and subprograms: the sustainment program and the restoration and modernization program. These programs
accomplish work through a combination of recurring maintenance contracts, contracted special projects and government forces. Facility sustainment includes regularly scheduled
maintenance, emergency services and cyclical major repairs to preserve shore infrastructure in working order over its expected service life. Restoration and modernization
includes repairs to restore facilities degraded by inadequate sustainment, excessive age or other damage. It also funds modifications required to support currently assigned
missions and implement new or higher facility standards.$$, NULL, NULL, $$O&M/FY26/Navy/OMNR_Book.pdf$$, 98, 104, $$95809dcc807e31ae47745cd7984f2d65ecfa34c4affb05581a226edfedb7b043$$, $$2026-05-10T00:20:58.246153+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_431$$, 2027, $$ADMINISTRATION - Supports the staffing and operation of Army National Guard (ARNG) management activities. Includes the cost of supplies, services, and equipment
used in providing ready and relevant military support to civil authorities, civil defense planning, and assistance in civil disturbances and emergencies. Also includes pay
and benefits for Department of the Army civilian employees and military technicians. Additionally, this resources Field Operating Activities' expenses including travel,
miscellaneous operating supplies for the ARNG, and official representation at authorized functions.

State Partnership Program (SPP) - Supports the National Defense Strategy, deterring strategic attacks against our homeland and our allies and partners through the
combatant commands and partner nations, to build defense capability and capacity and foster enduring personal and institutional relationships. Service Members of
the ARNG from all 50 States, three Territories, and the District of Columbia support partnerships with over 100 nations through the nation's military, security forces, and
disaster response organizations in a cooperative, mutually beneficial relationship.

Military Support to Civil Authority (Non-Standard Communications/Equipment) – Supports National Guard Bureau (NGB) and Joint Force Headquarters-State
capabilities to provide shared situational awareness to the Chief, National Guard Bureau as required for daily operations, Domestic Operations (DOMOPS), Continuity of
Operations (COOP) and mobilizations. Resources the capability to conduct Incident Awareness and Assessment (IAA) and maintain Joint Task Force -State deployable
interoperable communications capability.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 218, 219, $$9fcd57cc752b157ad119667198c127ffc6e729b7ff8ed27fc7b278bd84bba72f$$, $$2026-05-09T21:03:12.072253+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_2a2f$$, 2027, $$The Reserve Sealift program is comprised of two programs: the Ready Reserve Force (RRF), managed by the Department of Transportation's (DoT) Maritime Administration
(MARAD), and the Surge Fleet, managed by the Military Sealift Command (MSC). The Sealift vessels are maintained in a Reduced Operating Status (ROS). ROS ships have a
cadre crew assigned, are outported at a layberth, and undergo annual sea trials, periodic dock trials, and required periodic regulatory dry docking/inspections. The Sealift program
provides millions of square feet of cargo carrying capacity to U.S. Transportation Command (TRANSCOM) to transport Army, Marine Corps, and other unit's equipment, combat
support equipment and supplies when needed.

MARAD is the contracting agency for the acquisition of new used vessels. Used vessels are purchased with Ship Conversion, Navy (SCN). Used vessels are then modified and
placed in a ROS status in the Ready Reserve Force.

The FY27 Ready Reserve Force budget accounts for:
      (1) Completion of 6 Watson-class LMSRs from MSC to MARAD.
      (2) Deferring funding for scheduled FY27 drydocking 1 Bob Hope-Class LMSRs into FY28.
      (3) Deferring funding for scheduled FY27 drydocking CAPE H-class RO/RO into FY28.
      (4) Ending secure comms funding.

  MANDATORY FUNDING JUSTIFICATION:

  The FY 26 spend plan amount for Ready Reserve Force includes $785,052 thousand of discretionary and $150,000 thousand of mandatory (reconciliation) for a total of
  $935,052 thousand.$$, NULL, NULL, $$O&M/FY27/Navy/OMN_Book.pdf$$, 400, 409, $$4f8fe2e981c5701e023c9b17ed755903bddfdfda4f296d440cebd08fcfc8ed8d$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_reserve_bsm1$$, 2027, $$This subactivity group funds Facilities Sustainment, Restoration, and Modernization (FSRM) for the Marine Forces Reserve. Sustainment provides resources for maintenance and
repair activities necessary to keep an inventory of facilities in good working order. It includes regularly scheduled assessments and inspections, preventive maintenance tasks, and
emergency response and service calls for minor repairs. Sustainment also includes major repairs or replacement of facility components (usually accomplished by contract) that
occur periodically throughout the life cycle of facilities. This work includes regular roof replacement, refinishing of wall surfaces, repair and replacement of heating and cooling
systems, replacement of tile and carpeting, and similar work. Restoration includes repair and replacement work to restore facilities damaged by excessive age, natural disaster,
fire, accident, inadequate sustainment, or other causes. Modernization includes facility alteration solely to implement new or higher standards (including regulatory changes), to
accommodate new functions, or to replace building components that typically last more than 50 years (such as framework or foundations). Funding supports assessments that
identify and prioritize energy (including water) reduction opportunities and implement energy conservation measures to improve efficiency and reduce costs associated with the
use of electricity, natural gas, heating fuels, and potable water necessary to operate Marine Corps Reserves facilities.$$, NULL, NULL, $$O&M/FY27/Navy/OMMCR_Book.pdf$$, 34, 40, $$e66c944fdb3d5eeb6fb90999f3928557becec2a83574bb61f7a1d02abf0452c0$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_1a1a$$, 2027, $$Mission and Other Flight Operations include all Navy and Marine Corps Tactical Air (TACAIR) and Anti-Submarine Warfare forces, shore-based Fleet Air Support, and irregular
warfare. Funding provides flying hours to maintain required levels of readiness, enabling Navy and Marine Corps aviation forces to perform their primary missions as required in
support of national objectives. In addition, the Flying Hour Support program provides funding for transportation for equipment, travel for personnel, aircrew training systems,
commercial air services, and various information technology systems. These support accounts enable training for and execution of primary missions.

The Navy measures aviation readiness using the Defense Readiness Reporting System. Carrier Air Wings (CVWs) maintain varied training and readiness (T&R) levels in
accordance with the Optimized Fleet Response Training Plan (OFRTP), providing adequately trained aircrews across a 36-month deployment cycle.

Marine Corps TACAIR readiness differs in approach and requires maintaining a steady readiness profile for rapid and effective deployment on short notice in support of
operational plans or contingency operations. The Marine Corps Aviation Plan (AVPLAN) directs the T&R requirements and resources to attain readiness levels over a 12-month
snapshot of a USMC 36-month squadron training cycle. The AVPLAN aligns with Department requirements by implementing a comprehensive, capabilities-based training system
that provides mission skill-proficient crews and combat readiness to the Combatant Commanders.$$, NULL, NULL, $$O&M/FY27/Navy/OMN_Book.pdf$$, 42, 53, $$f03a07e18f8e49d41c23dd6dd58fa740a98a81378235ba176183939ee4d2b243$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_reserve_bssr$$, 2026, $$Base Operating Support includes funding for shore activities that sustain sea, air, and land operations in support of operating forces. Base Support includes port and airfield
operations, operation of utility systems, public works services, base administration, supply operations, and base services such as transportation, environmental and hazardous waste
management, security, personnel support functions, bachelor quarters operations, morale, welfare and recreation operations, and disability compensation.$$, NULL, NULL, $$O&M/FY26/Navy/OMNR_Book.pdf$$, 105, 113, $$8e9b6237f7b1a90e7cfa7818bb967a65d3588ad42b3177895098fcaffab54cc6$$, $$2026-05-10T00:20:58.246153+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_socom_umbrella$$, 2027, $$The United States Special Operations Command (USSOCOM) develops and employs the world's finest Special Operations Forces (SOF) to conduct global special
operations and activities as part of the Joint Force, in concert with the U.S. Government Interagency, Allies, and Partners, to support persistent, networked, and
distributed combatant command operations and campaigns against state and non-state actors to protect and advance U.S. policies and objectives. In support of
this mission, the USSOCOM serves as the Coordinating Authority for Countering Violent Extremist Organizations (C-VEO), Countering Weapons of Mass
Destruction (CWMD), and internet-based Psychological Operations (PSYOP) formerly Military Information Support Operations (MISO). The budget request
reflects the Secretary of War focus on restoring the warrior ethos, rebuilding military capabilities, and enhancing national deterrence while simultaneously
balancing readiness to create a strategic, asymmetric advantage for the nation by strengthening our force and their families, bolstering integrated deterrence
capabilities, and ensuring our enduring advantage through innovation and modernization.

1. Budget Activity 01 (BA-01)/Operating Forces - The units and/or functions associated with these Sub-Activity Groups (SAG) are:

    A. 1PL6 - Combat Development Activities - Includes Joint and Component manpower authorizations, SOF-peculiar equipment, necessary facilities, and the
    associated costs specifically identified and attributable to the development of combat doctrine, organizational concepts, materiel requirements, and other
    developmental activities related to SOF. Also includes activities to support experimentation, tests, and project evaluations necessary to develop and/or
    validate new doctrine and organizations for special operations.

    B. 1PLS - Cyberspace Activities - Includes cyber resources associated with computer network defense and information assurance, service contracts
    specifically intended to secure, defend, and preserve data, networks, net-centric capabilities, and other designated systems by ensuring security controls and
    measures are in place, and taking internal defense actions on the SOF Information Environment (SIE). This includes access to system controls, monitoring,
    administration, and integration of cybersecurity into all aspects of engineering and acquisition of cyberspace capabilities. In addition, these activities include
    implementation, evaluation, and disposal of information technology and services, as well as information resources management, and the management,
    storage, transmission, and display of data and information.

    C. 1PLU - Intelligence - Includes all USSOCOM Headquarters (HQs) and/or Component funding to sustain USSOCOM equipment, systems, logistics, and
    maintenance required to perform/sustain USSOCOM Military Intelligence Programs (MIP). These programs support the Secretary of War's intelligence,
    counterintelligence, and related intelligence responsibilities. These programs, projects, and activities provide capabilities to meet SOF warfighter operational
    and tactical requirements more effectively. These include intelligence, surveillance, and reconnaissance (ISR) systems and sustainment; processing,
                                                                                                                                                        OP-5 Exhibit
                                                                                                                                                           SOCOM

                                                                                  1

                                                      United States Special Operations Command$$, $$$$, NULL, $$O&M/FY27/DW/Vol1_Part1/SOCOM_OP-5.pdf$$, 5, 8, $$e4bcdd1c4c3e861ae9b30ceb6478eb7c76c12180227f9ea42fb0bd69c0d0aa03$$, $$2026-05-10T00:59:04.217246+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_reserve_1a4n$$, 2027, $$Reserve Engineering Technical Services - This program provides on-site technical information, instruction and training (formal and on the job) to aviation maintenance personnel
at the organizational and intermediate levels of maintenance for a network of 23 detachments dispersed worldwide. The purpose of the training is to elevate the technical
knowledge and skills of Navy and Marine aviation maintenance technicians in the installation, maintenance, repair, and operation of all types of aviation and associated support
equipment. Engineering Technical Services (ETS) tasks are performed by Contractor Engineering Technical Service (CETS) and Navy Engineering Technical Service (NETS)
personnel.

Aircraft Depot Operations Support - The reserve support services program provides unscheduled services to the reserve forces and enhances operational readiness by providing
expeditious solutions for the correction of unplanned depot maintenance problems incurred in the field. Customer service includes the costs of nonscheduled work for depot-level
industrial services provided directly to reserve force activities for immediate needs both in hardware rework and technical/engineering services. This service is provided for the
accomplishment of emergency check/test and minor repair of aeronautical material and provides special industrial processes such as plating, heat-treating, nondestructive testing,
and machine shop services. Ferry flights includes the costs of travel, per diem, and fuel associated with flying aircraft to an organic rework facility prior to maintenance or
returning aircraft to the reserve fleet following maintenance.$$, NULL, NULL, $$O&M/FY27/Navy/OMNR_Book.pdf$$, 31, 37, $$8d0909c3c4db3ef18165895e9c067798239a52b33afc8bc565d2d1564a97438c$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_3c1f$$, 2027, $$Marine Corps recruiting is responsible for recruiting, processing, and accessing highly qualified individuals in sufficient numbers to meet the established strength levels for officer
and enlisted personnel of the Marine Corps and Marine Corps Reserve. Operations funded in this sub-activity include expenses incurred in developing a proficient and current
military recruiting force, to include recruiter sales training curriculum and materials, travel, civilian labor, leased vehicles, communications, applicant processing costs, office
furniture, administrative supplies, equipment, recruiter out-of-pocket expenses and awards.

 Marine Corps advertising supports all recruiting missions, including enlisted and officer, active duty and reserve. Advertising initiatives cover the full range of marketing and
communications services in support of Marine recruiters and officer selection officers. It is intended to raise brand awareness in qualified enlisted and officer prospects, generate,
distribute, and convert leads, and leverage emerging trends and evolving consumption patterns. Advertising programs and tactics are grouped into three primary and
complementary categories: Awareness (broadcast/streaming media, PSA, online/social, outdoor, etc.), Lead Generation (direct mail, database, call center, prospect websites, digital
engagement, etc.) and Recruiter Support (collateral materials, incentive items, promotional items, online applications, etc.). A marketing research program delivers strategic
insights necessary to guide the formulation of effective programs and supports the content team which captures the range of film, video, photography, and digital assets needed.$$, NULL, NULL, $$O&M/FY27/Navy/OMMC_Book.pdf$$, 139, 146, $$e2d73df864afecf9d90674d561fc485ed2ca9720558e374970252b23390361ab$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_114$$, 2027, $$THEATER LEVEL ASSETS - Funds training and operations of Theater Level Assets by leveraging live, virtual, and constructive capabilities to conduct collective training
focused on Multidomain Operations capabilities. Funds Combined Arms Training Strategy collective training events aligned based on Continuous Transformation and
Directed Readiness Table requirements. The Army National Guard (ARNG) funds ground units to conduct collective training and achieve designated training proficiency
levels. Includes incremental costs of Title 32 personnel associated with pre-deployment unit training and support.

Home Station Training - Resources Modification Table of Organizational Equipment (MTOE) units to conduct collective training. This includes maintenance repair parts
and petroleum, oil, lubricants, Soldier Support per capita costs, Army National Guard (ARNG) Combat Training Center (CTC) and Combat Readiness Exercises (CRX),
command funded contracts to sustain routine day-to-day operations, and other activities directed by Army and Army National Guard leadership. These resources directly
support each commander's ability to improve unit training and readiness. Includes funding to enable a variety of Echelons Above Corps units to maintain readiness for
Theatre Operations. Theater supporting units include military police, military intelligence, missile/space, information operations, and logistics capabilities.

Contractor Logistics Support - Funds contractor logistics support of select equipment such as Javelin Missiles, High Mobility Artillery Rocket System, Tube-Launched,
Optically-Tracked, Wire-Guided Missile Improved Target Acquisition System, and Sentinel Radars.

MANDATORY FUNDING JUSTIFICATION:

The FY 2026 spend plan amount for Theater Level Assets includes $86,182 thousand of discretionary and $4,445 thousand of mandatory for a total of $90,627 thousand.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 79, 80, $$679b69bf66f6e1b027d8bb83cca776c45fbc7d247f26799f3698cb68351ddc9e$$, $$2026-05-09T21:03:12.072253+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_reserve_4a1m$$, 2026, $$This sub-activity group provides resources for the operation of the Office of the Chief of Navy Reserve. The Chief of Navy Reserve provides policy, control,
administration, and direction including the management of all resources (manpower, hardware, and facilities) to facilitate an optimum training posture and
mobilization readiness. To aid in readiness, funding supports Navy Recruiting Reserve Command (NRRC) and five Reserve Talent Acquisition Groups (RTAGs)
commands to fully exercise Navy Reserve recruiting capabilities. The positions allow for a more expansive deployment of RTAGs, intensifying efforts in key
regions, capitalizing on emerging opportunities, and bolstering responsiveness to dynamic shifts in the recruitment landscape. This aligns with the commitment to
securing a diverse and highly qualified Reserve Force. Funding also provides for Defense Finance and Accounting Services (DFAS) for the Navy Reserve.$$, NULL, NULL, $$O&M/FY26/Navy/OMNR_Book.pdf$$, 114, 120, $$3d16276b666fec214110bbbd408fa9c2ad349963ae1fa0d115ee780117afe37a$$, $$2026-05-10T00:20:58.246153+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_115$$, 2027, $$LAND FORCES OPERATIONS SUPPORT - Supports sustainment maintenance of centralized maintenance facility equipment for 50 States, three Territories, and the
District of Columbia. The Direct Support and General Support maintenance Table of Distribution and Allowances equipment is reported under base operations program
elements. This includes maintenance support of equipment directly related to mission performance recorded on organization property books normally deployed with their
units. Provides fuel and repair parts materiel to Field Maintenance Shops, Army National Guard Aviation Support Facilities, Combined Support Maintenance Shops, Unit
Training Equipment Sites, and Maneuver Area Training Equipment Sites.

Aviation Maintenance Contract Support - Funds Contractor Logistics Support maintenance support for rotary wing aircraft in Army tactical aviation units. Civilian
contract personnel provide all functions and levels of maintenance support for Army rotary wing aircraft during home station training. Also funds the contractor logistics
support contracts for Apache (AH-64D), Blackhawk (UH-60), and Chinook (CH-47) aircraft.

Home Station Training - Resources Modification Table of Organizational Equipment (MTOE) units to conduct collective training. This includes maintenance repair parts
and petroleum, oil, lubricants, Soldier Support per capita costs, Army National Guard (ARNG) Combat Training Center (CTC) and Combat Readiness Exercises (CRX),
command funded contracts to sustain routine day-to-day operations, and other activities directed by Army and Army National Guard leadership. These resources directly
support each commander's ability to improve unit training and readiness. Includes funding to enable installation maintenance organizations and the maintenance of tactical
equipment and organic land forces vehicles that can expect to be deployed with units.

MANDATORY FUNDING JUSTIFICATION:

The FY 2026 spend plan amount for Land Forces Operations Support includes $345,261 thousand of discretionary and $13,548 thousand of mandatory for a total of
$358,809 thousand.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 90, 91, $$dc01a1af3ab13d78b243acc719cf33fb370ff2d9fe0418aa4b80c7109285842b$$, $$2026-05-09T21:12:37.492901+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_3b1d$$, 2027, $$Upon completion of Recruit Training, Marines are assigned to Marine Combat Training (MCT) or Infantry Training Battalion at the Schools of Infantry, East or West. Upon
completion of MCT, enlisted Marines are assigned to courses of instruction to acquire the requisite skills to meet the minimum requirements of a specific Military Occupational
Specialty (MOS), as outlined in approved programs of instruction (POI). Schools supporting MOS training reside on USMC installations and aboard sister service installations
where training in certain MOS skills have been consolidated or co-located, such as aviation mechanics and artillery training. For officers, once Officer Acquisition Training is
completed, they report to the Basic School at Quantico. Once the Basic School is complete, they are assigned to courses at USMC installations or other service installations for
training to acquire their assigned MOS skills. This sub-activity funds initial MOS, advanced MOS, and skills progression qualifying courses for all Marines and consists of routine
administrative services, civilian labor, staff training, minor property, classroom furnishings, classroom equipment, and travel required to support POI administration. Costs include
student support, resident instruction, reproduction of training aids and literature, purchase of supplies, equipment maintenance and operations, civilian pay and benefits, contractual
services in support of advance parachute, intelligence, and communications training, in support of POIs. Additionally, the Marine Corps provides operation and maintenance
support to personnel at U.S. Naval Air Station, Pensacola, Florida and U.S. Naval Air Station, Corpus Christi, Texas for flight training (the majority of flight training costs are
incurred by the U.S. Navy).$$, NULL, NULL, $$O&M/FY27/Navy/OMMC_Book.pdf$$, 113, 120, $$5ff6c729cdeac2f18dc77dccf9102210a649620617d61fe7c9b2c53628ef36b0$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_sisc_umbrella$$, 2027, $$The Support for International Sporting Competitions, War (SISC) account is funded with a no-year appropriation that provides continuing
Department of War (DoW) support to national and international sporting events that are either certified by the Attorney General or supports
specific organizations, such as: the Special Olympics, Paralympics, and the United States Olympic and Paralympic Committees (USOPC) through
the Paralympic Military Program.

Funds in the amount of $11.5 million are still available from the FY 2015 and FY 2023 Consolidated Appropriations Acts. The Department is not
requesting any appropriated funds in FY 2027 due to the available balances in the account from the Consolidated Appropriations Acts for FY 2015
and FY 2023. In FY 2026, the Department is supporting 18 Paralympic sporting events sanctioned by the USOPC through the Paralympic Military
Program, the 2026 Winter Paralympics in Milano Cortina, Italy, the Special Olympics USA Games, and the Special Olympics USA National Team
Trials with an estimated combined cost of $1.7 million. In FY 2027, the Department expects to support 19 Paralympic sporting events sanctioned
by the USOPC through the Paralympic Military Program as well as the 2027 Special Olympics World Games in Santiago, Chile with an estimated
combined cost of $2 million. The International Sporting Competitions planning cycles do not fully align with the DoW budget cycle, which can
result in year of execution requests for support.

These funds support safety, security and logistical requirements for certain sporting competitions. Under the provisions of 10 U.S.C. Section
2564, the Department has the authority to assist Federal, state and/or local agencies in support of civilian sporting events if the Attorney General
certifies that such assistance is necessary to meet essential security and safety needs.

The Department can also provide support to the Special Olympics, the Paralympics, a sporting event sanctioned by the U.S. Olympic and
Paralympic Committee, through the Paralympic Military Program, and/or any national or international Paralympic sporting event that meet
requirements outlined in 10 U.S.C. Section 2564, as amended by Public Law 110-181 Section 372. Support for these events are eligible for DoW
support and exempt from Attorney General certification.$$, NULL, NULL, $$O&M/FY27/DW/Vol1_Part2/SISC_OP-5.pdf$$, 2, 4, $$96c741f3ee2a9650afb419e49be47fd37d6f4b468cfc4efbbbb55d51720ccb28$$, $$2026-05-09T21:12:37.492901+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_116$$, 2027, $$AVIATION ASSETS - Funds the training and operations of Aviation Assets leveraging live, virtual, and constructive capabilities to conduct collective training focused on
Multidomain Operations capabilities. Funds training and operations within both the Ground Homes Station Training and Aviation Flying Hour Programs required to achieve
readiness across the Army National Guard's (ARNG) aviation units and all organic forces associated units within. The Army National Guard (ARNG) funds ground units to
conduct collective training and achieve designated training readiness levels. Includes incremental costs of Title 32 personnel associated with pre-deployment unit training
and support. Funds fuel, supplies, and repair parts to support unit trainings, maintenance programs and other special training activities, and the cost to operate tactical
headquarters. This program does not include the Contract Logistics Support maintenance costs for fixed wing aircraft and the Lakota (UH-72A) fleet - these costs are
budgeted by the Active Component. The ARNG funds aviation units to conduct Combined Arms Training Strategy training based on the Continuous Transformation and
will meet Directed Readiness Table requirements.

Home Station Training - Resources Modification Table of Organizational Equipment (MTOE) units to conduct collective training. This includes maintenance repair parts
and petroleum, oil, lubricants, Soldier Support per capita costs, Army National Guard (ARNG) Combat Training Center (CTC) and Combat Readiness Exercises (CRX),
command funded contracts to sustain routine day-to-day operations, and other activities directed by Army and Army National Guard leadership. These resources directly
support each commander's ability to improve unit training and readiness. Includes funding to enable heavy medium and light Combat Aviation Brigades, providing full
spectrum aviation support to maneuver units. Also supports Echelon Above Brigade aviation units and multi-functional support brigades with organic aviation, aviation
support, aviation maintenance support and aviation operations support theater aviation operations.

MANDATORY FUNDING JUSTIFICATION:

The FY 2026 spend plan amount for Aviation Assets includes $1,114,864 thousand of discretionary and $32,087 thousand of mandatory for a total of $1,146,951
thousand.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 101, 102, $$44270f923ca79760cbfef1890c6d8fb6fb1e1e9adc866934e3b71d31bedfdb8e$$, $$2026-05-09T21:12:37.492901+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_113$$, 2027, $$ECHELONS ABOVE BRIGADE - Funds the training and operations of Echelons Above Brigade operational units whose mission is to provide critical, actionable
intelligence, force protection, and area logistics support to Division Brigade Combat Teams through force generation, while leveraging live, virtual, and constructive
capabilities to conduct training focused on Multidomain Operations capabilities. Funds Combined Arms Training Strategy (CATS) collective training events aligned based
on Continuous Transformation. The Army National Guard (ARNG) funds ground units to conduct collective training and achieve designated training proficiency
levels. Included in this sub activity group are operation and maintenance costs aligned with CATS collective training requirements for critical tactical and national assets,
such as: Air Defense Battalions and Chemical, Biological, Radiological/Nuclear, and Explosive units/operations required to protect both deployed units and the homeland.
It also funds Army support to military police units providing force protection.

Home Station Training- Resources Modification Table of Organizational Equipment (MTOE) and units to conduct collective training. This includes maintenance repair
parts and petroleum, oil, lubricants, Soldier Support per capita costs, Army National Guard (ARNG) Combat Training Center (CTC) and Combat Readiness Exercises
(CRX), command funded contracts to sustain routine day-to-day operations, and other activities directed by Army and Army National Guard leadership. These resources
directly support each commander's ability to improve unit training and readiness. Includes funding to enable a variety of Echelon Above Brigade units to maintain readiness
for Multi-Domain Combined Arms Operations. Corps include chemical, engineer, medical, signal, finance, military police, military intelligence, missile/space, air defense
artillery, logistics, combat, combat support, and combat service support capabilities.

Lodging In Kind - Funds support for the Department of War Instruction 1225.9 "Billeting for Reserve Components Members" to provide billeting to Reserve Component
personnel who travel more than 50 miles from the member's residence to perform active duty or inactive duty training.

MANDATORY FUNDING JUSTIFICATION:

The FY 2026 spend plan amount for Echelons Above Brigade includes $850,330 thousand of discretionary and $46,822 thousand of mandatory for a total of $897,152
thousand.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 67, 68, $$88cb9c35c472dba5ddfc40481dadde052b7f882d6ba2994188169c2d40f0caa2$$, $$2026-05-09T21:12:37.492901+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_reserve_4b3n$$, 2026, $$This sub-activity group funds logistics operations and program management at Naval Supply Systems Command (NAVSUP) Reserve Component field activities and Headquarters
in the areas of supply operations, contracting, resale, fuel, card management, security assistance, conventional ordnance, food service and other quality of life programs. Through
its Products and Services Initiative, NAVSUP is restructuring and realigning its organization to most effectively and efficiently accomplish its purpose of delivering combat
capability through logistics to maritime forces, and to support the CNO's guidance to reduce Navy total ownership cost.$$, NULL, NULL, $$O&M/FY26/Navy/OMNR_Book.pdf$$, 129, 135, $$57ed6546a582590015cbd9a90e6ec7970eef0ceeb173924bf48dde60768352ea$$, $$2026-05-10T00:20:58.246153+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_af_active_11r$$, 2026, $$Facilities Sustainment, Restoration and Modernization (FSRM) functions include facility and infrastructure sustainment, restoration and modernization, and demolition
activities at all Air Force installations, including large life-cycle repair for all Active Force Major Commands and the United States Air Force Academy (USAFA). Beginning
in FY 2022, funding for Space Force bases was transferred from the Air Force to the Space Force. FSRM activities ensure installation facilities, utility systems, and
infrastructure are capable of fully supporting mission requirements throughout their economic lives.

Sustainment is performed through a combination of organic workforce and contract support and includes the maintenance and repair activities necessary to keep an
inventory of facilities in good working order. It includes regularly scheduled adjustments and inspections, preventive maintenance tasks, and emergency response and
service calls for minor repairs. It also includes major repairs or replacement of facility components (usually accomplished by contract) that are expected to occur
periodically throughout the life cycle of facilities. This work includes replacement, refinishing, repairing and replacement of heating and cooling systems, tile, carpeting, and
similar types of work. It does not include environmental compliance costs, facility leases or other tasks associated with facilities operations (such as custodial services,
grounds services, waste disposal and the provision of utilities).

Restoration is the restoration of real property to such a condition that it may be used for its designated purpose. This includes repair or replacement work to restore
facilities damaged by inadequate sustainment, excessive age, natural disaster, fire, accident or other causes.

Modernization is the alteration or replacement of facilities solely to implement new or higher standards, to accommodate new functions or to replace building components
that typically last more than 50 years (such as the framework or foundation). Modernization also includes infrastructure repairs and minor construction to accommodate
changes in mission requirements, including new mission beddowns. Modernization is critical to ensure aging facilities remain capable of supporting mission requirements
as they evolve over the long lives of facilities and infrastructure systems.

Recapitalization is the major renovation or reconstruction activities (including facility replacements) needed to keep existing facilities modern and relevant in an
environment of changing standards and missions. Recapitalization extends the service life of facilities or restores lost service life. It includes restoration and modernization
of existing facilities.

Demolition is performed primarily by contract. Facilities and infrastructure are demolished to free space for future construction and to eliminate obsolete facilities from the
real property inventory. Demolition is a key component of the Air Force strategy to consolidate functions, vacate excess and obsolete facilities, and focus sustainment,
restoration and modernization funding on facilities intended to function well into the future.

Evaluation Formulas:
The Department of Defense (DoD) Facilities Sustainment Model (FSM) is used as the standardized model for forecasting Facilities Sustainment resource requirements.

The FSM uses the following formula to develop the sustainment requirement:
Annual Sustainment Requirement = Facility Quantity x Sustainment Cost Factor x Location Factor x Inflation$$, $$$$, NULL, $$O&M/FY26/Air Force/FY26 Air Force Operations and Maintenance Vol I.pdf$$, 126, 129, $$c7ca7397611fed5841c8b41ce03b8f0fbde70dfd41ea22bb22147078ff7b5e85$$, $$2026-05-10T00:20:58.246153+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_434$$, 2027, $$OTHER PERSONNEL SUPPORT - Supports the Army National Guard's (ARNG) recruiting, retention, and activities to achieve unit-level strength readiness, as well as
overall ARNG officer, warrant officer, and enlisted end strength. Funding resources advertising, marketing, and recruiting and retention operations and expenses. The
program also resources the ARNG's family, community, and Soldier programs, the Sexual Harassment and Assault Prevention Program, and the Transition Assistance
Program (TAP) (formerly the Soldier for Life-Transition Assistance Program). Resources include support for Department of the Army Civilian and Military Technicians
personnel costs and funding for equipment to sustain required levels of operational readiness.

Army Marketing Program - Supports the development and delivery of ARNG-specific messaging with appropriate calls-to-action across key markets to generate qualified
leads. The ARNG's large geographic footprint necessitates the use of localized marketing strategies supported by multimedia advertising campaigns to recruit, retain, and
manage attrition to meet annual end-strength requirements.

Family, Community, and Soldier Programs - Support that enhances the quality of life for service members and their families during peacetime and upon mobilization.
This includes family, personal, financial, and community readiness, deployment cycle support, crisis intervention, outreach, training, management, information, referral and
follow-up, life skills education, review and analysis of program effectiveness, and volunteer program management.

Recruiting and Retention Support - Recruiting and retention operations support meals and lodging of applicants who are processed through Military Enlistment
Processing Stations; training and office equipment; commercial facility rental; and expenses supporting recruiting, retention, and attrition management.

Sexual Harassment/Assault Response and Prevention (SHARP) - Provides resources to implement recommendations from the Independent Review Commission on
Sexual Assault in the Military (IRC-SAM). Resources for SHARP are engaged along several lines of effort: Prevention, Response, Accountability, Support and Care of
Victims, and Climate and Culture.

Transition Assistance - Supports career and financial readiness for Soldiers and their Family members. Provides the assistance necessary to obtain civilian employment
and maximize the use of benefits earned through ARNG service.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 238, 239, $$a4beb1aa5f894786b7c109d547b4f8eceb3e3dd164ca59c0bc27b12b019f5e71$$, $$2026-05-09T21:12:37.492901+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_133$$, 2027, $$MANAGEMENT AND OPERATIONAL HEADQUARTERS - Supports the 50 States, three Territories, and District of Columbia Joint Force Headquarters (JFHQ) to
provide command and control of all Army National Guard (ARNG) forces in the State or Territory for the Governor during all operations. Resources include support for
Department of the Army Civilian and Military Technicians personnel costs and funding for equipment to sustain required levels of operation and maintenance
readiness. Performing the synchronization and integration necessary to ensure that manpower, equipment, facilities, and other resources are available to produce trained
and ready Soldiers and units.

Boy/Girl Scouts of America Activity Support - Funds the quadrennial support of the National Scout Jamboree, which includes aviation, support units, transportation,
and medical units.

Civilian Injury and Illness Compensation - Resources employee compensation benefits related to work injuries or work-related illnesses.

Command Support - Supports command operations with digital systems to conduct strategic planning and organizational structure analysis. This empowers decisions to
assign operational tasks to the most qualified units and personnel.

Military Funeral Honors Program - Supports military funeral honors for Army veterans. The ARNG Funeral Honors Program conducts the largest portion of Army
ceremonies due to geographic alignment and cost effectiveness. Resources include stipends for some non-military personnel (retirees and veterans service organizations)
performing the honors, in addition to per diem, travel, supplies, and contract expenses.

Sexual Harassment/Assault Response and Prevention (SHARP) - Provides resources to implement recommendations from the Independent Review Commission on
Sexual Assault in the Military (IRC-SAM). Resources for SHARP are engaged along several lines of effort: Prevention, Response, Accountability, Support and Care of
Victims, and Climate and Culture. These efforts include support of legacy SHARP programs: prevention strategy development, policy, oversight, manpower, compliance,
accountability, victim advocacy support, and training.

Suicide Prevention and Response - Provides resources to implement the recommendations from the Suicide Prevention and Response Independent Review
Commission (SPRIRC). Includes state-wide suicide prevention training synchronization, compliance monitoring, policy maintenance, and contract support for analytics;
with a goal of modernizing the content and delivery of training for suicide prevention, supporting postvention efforts, and building a more resilient force.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 176, 177, $$4c0b495ace84b82854d1fb9ef8b81b5ef717129a7bf89cde18573b38e1dbf88b$$, $$2026-05-09T21:12:37.492901+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_ng_123$$, 2027, $$LAND FORCES DEPOT MAINTENANCE - Funding supports the repair and overhaul of Army National Guard equipment and mitigates the impacts of high levels of
equipment usage in support of training requirements. The Depot maintenance program facilitates achievement of the Army's expected equipment life cycle. The program is
a "repair and return to user" process as opposed to a supply exchange transaction. Depot Maintenance supports the Army's Modernization and Equipping Strategies by
sustaining the availability and reliability of fielded systems.

Aircraft - End Items - Provides overhaul, repair, rebuild, and depot level field teams for aviation platforms, aircraft survivability equipment, and aviation secondary items.
These platforms provide air superiority, ground force security, and aerial escort capability. Examples include the AH-64 Apache, CH-47 Chinook, UH-60 Blackhawk, and
Aviation ground support equipment.

Combat Vehicles - End Items - Provides overhaul, repair, and depot level field teams for maneuver vehicles. These platforms provide mobility, lethality, and attack
capability. Examples include the M3A3 Bradley Fighting Vehicles, the M88A1/M88A2 Heavy Equipment Recovery Combat Utility Lifting, and the Paladin M109A6 Howitzer
Medium Self Propelled. Sustains end items and supported systems including Family of Medium Tactical Vehicles, High Mobility Multipurpose Wheeled Vehicles, line-haul
tractors, trailers, and Heavy Expanded Mobility Tactical Trucks.

Communications - Electronic End Items - Funds end items supporting sustainment readiness of Command, Control, Communications, Computers, Cyber, Intelligence,
Surveillance and Reconnaissance (C5ISR) across the life cycle of C5ISR systems.

Missiles - End Items - Provides overhaul, repair, rebuild, and depot level field teams for air defense platforms, rocket systems, and missiles. These platforms provide
protection for ground forces and critical assets from tactical ballistic and cruise missiles through long- and short-range missile defense, precision fires, and integrated
airspace management. Examples include the High-Mobility Artillery Rocket System and Airspace Management equipment.

Other - End Items - Funds the maintenance overhaul of other end items including the Test, Management and Diagnostic Equipment, calibration, the Control Humidity
Preservation program, Radiation Safety program, construction equipment, and general equipment end items. Supported systems include, but are not limited to, Tactical
Water Purification System, small arms, towed howitzers, and troop support equipment.

MANDATORY FUNDING JUSTIFICATION:
The FY 2026 spend plan amount for SAG 123 includes $179,622 thousand of discretionary and $126,474 thousand of mandatory for a total of $306,096 thousand.$$, NULL, NULL, $$O&M/FY27/Army/National Guard Army Operation and Maintenance.pdf$$, 141, 142, $$4c40bfc6491a0aada4796186282169cef8a98f64e8cd6e05b77e19d65563e977$$, $$2026-05-09T21:12:37.492901+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_1a2a$$, 2027, $$Fleet Air Training includes Fleet Replacement Squadrons (FRS) located throughout the country which train replacement aircrews for each Navy and Marine Corps
type/model/series in weapons tactics, weapons delivery, and carrier landing qualifications. Tactical Air/Anti-Submarine Warfare force level requirements establish student levels
by authorized, aircrew personnel rotation rates, and student output from the Undergraduate Pilot/Navy Flight Officer Training Program. Flight hours also facilitate specialized
schools such as the Naval Aviation Warfighting Development Center (NAWDC) for adversary support. Fleet Air Training includes the material costs to support simulator
maintenance.
Fleet Air Training also includes funding for Chief of Naval Air Training (CNATRA) flight operations for undergraduate pilot and flight officer training, and test pilot-transition
training. Undergraduate pilot training spans multiple fiscal years. The longest training pipeline is T-45 Goshawk pilot training at 87 weeks in duration. Flight operations consist
of fuel, flight gear, parts and material support for organizational and intermediate maintenance, aviation depot level repairables, and contractor maintenance support. Flight hours
for each fiscal year are calculated based on phase output requirements for undergraduate pilot and flight officer production rates prescribed by the Chief of Naval Operations.
Funds for flight support include academic training, contractor maintenance of training simulators, contract flight simulator instructors, consumable supplies, civilian salaries and
operating costs for CNATRA headquarters and Training Air Wings.
Also included in Fleet Air Training is funding for the Navy's Flight Demonstration Squadron (NFDS). The NFDS trains for and conducts aerial flight demonstrations across the
United States to enhance recruiting and increase public awareness of the U.S. Navy and other military departments.$$, NULL, NULL, $$O&M/FY27/Navy/OMN_Book.pdf$$, 54, 67, $$3961a800f0bcd63641615a8a13b4603d8d9f1530d149bc04604ae4e6c9d2645e$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_army_reserve_451$$, 2027, $$Sub-program of 431 (Administration). FY2027 estimate: $0. This sub-activity group (451, Other Personnel Support) appears as a line item within the parent SAG's O-1 Summary table — see Reserve Army Operation and Maintenance.pdf line 454: "2080 451 Other Personnel Support                                                                  4                  0                0". Per the parent SAG's OP-5 narrative, sub-program rollups of this kind do not receive standalone descriptions; refer to the parent SAG (431) narrative for context. Source: O&M/FY27/Army/Reserve Army Operation and Maintenance.pdf line 454 (line-item citation) + parent SAG 431 narrative. synth_subprogram v41.$$, NULL, NULL, $$O&M/FY27/Army/Reserve Army Operation and Maintenance.pdf$$, 454, 454, $$597e91d2f5dab46d338efa964bef9d1d814f8619ce0f86dbb00fb4eeedd27906$$, $$2026-05-10T01:03:08.635372+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_1a1a$$, 2027, $$The Operational Forces compose the core element of the Marine Corps, which is the Marine Air Ground Task Force (MAGTF). The MAGTF is a scalable, task organized force
generation construct that permits a composite assembly of forces from the four MAGTF elements—Command Element (CE), Ground Combat Element (GCE), Logistics Combat
Element (LCE), and Aviation Combat Element (ACE)—to rapidly deploy ready forces in support of combatant commanders. The scalable nature of the MAGTF offers tiered force
and capability levels and provides a continuous forward presence via a Marine Expeditionary Unit (MEU), an amphibious capable and self-sustainable Marine Expeditionary
Brigade (MEB), an enduring middleweight Marine Expeditionary Force (MEF), or a Special-Purpose MAGTF (SPMAGTF). The MAGTF is a balanced force structure that allows
it to respond to the full spectrum of conflicts across the globe, from conventional to irregular warfare, anti-access/area denial to regional deterrence, and security cooperation
exercises to humanitarian relief. The Operational Forces sub-activity group funds training and routine operations; maintenance and repair of organic ground equipment; official
travel, including travel for reservists mobilized under 12304b authority for active component requirements; information technology repair and replacement; and
replenishment/replacement of unit and individual equipment and supplies in order to meet the Commandant of the Marine Corps Title X responsibilities to train, equip, and deploy
ready forces in support of national security interests. Additionally, the Operational Forces sustain unique capabilities that provide special operations-capable forces to
Commander, US Special Operations Command (USSOCOM).

MANDATORY FUNDING JUSTIFICATION:

The FY 2026 spend plan amount for Operational Forces, Marine Corps includes $1,909,404 thousand of discretionary and $507,851 thousand of mandatory
(reconciliation) for a total of $2,417,255 thousand.$$, NULL, NULL, $$O&M/FY27/Navy/OMMC_Book.pdf$$, 27, 38, $$ec3229a0592249eaa07879447954db634f80acb464f7669bda009b36bd1625e0$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_1b2b$$, 2027, $$Ship Operational Support and Training provides for detailed pre-planning, engineering, training and range operations necessary to ensure all operating force ships and nuclear
attack submarines and their crews are operating at high levels of readiness. Specific programs funded include submarine support, surface ship support, and Receipt, Segregation,
Storage, and Issue (RSSI).

Submarine Support includes the Submarine Operations and Safety Program, which provides technical direction and engineering support to safely extend the operating interval
between shipyard overhauls for operational submarines. It also manages advanced planning and engineering for overhauls and other submarine availabilities. The Deep
Submergence Systems Program (DSSP) provides program and technical management to support the Fleets' capabilities in the areas of submarine rescue, deep ocean search,
inspection, object recovery, and scientific research and data gathering for a variety of manned and unmanned deep submergence vehicle programs. This program supports Virginia
Class (VACL) submarine obsolescence materials public shipyard outsourcing work in an effort to support Navy's 15-year maintenance plan thru the FYDP.

Surface Support includes the AEGIS Program, which supports the Navy's AEGIS cruiser and destroyer fleet. The AEGIS Program funds a variety of requirements for AEGIS
cruisers and destroyers from training officers and crew members to operate the AEGIS weapons system critical equipment testing after depot maintenance availabilities.

The Fleet Ordnance Receipt, Segregation, Storage, and Issue (RSSI) program provides for ordnance movement, handling, storage, and disposal as required by Fleet operations and
for inventory management. The RSSI program supports personnel and material to manage the Navy's worldwide disposable ordnance inventory and accomplishes required reuse
and declassification in the most effective and economical manner consistent with safety, security, and environmental regulations and constraints.$$, NULL, NULL, $$O&M/FY27/Navy/OMN_Book.pdf$$, 115, 124, $$b0436061cae5a640c1598ebd33c288af670ec454fa9aa59e14762cc53cd4900e$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_1cch$$, 2027, $$USINDOPACOM Core Operations
Funding in this sub-activity group supports the operation and administration of United States Indo-Pacific Command (USINDOPACOM). Resources finance headquarters staff—
including civilian personnel—along with travel, supplies, training, and other essential mission-support requirements that enable the Command to execute theater-wide operational
responsibilities.

Civilian Harm Mitigation and Response (CHMR)
Funding supports Civilian Harm Mitigation and Response (CHMR) staffing requirements across Department of the Navy (DON) components. Initial requirements include
full-time equivalents (FTEs) necessary to implement the CHMR-Action Plan (CHMR-AP). Consistent with the CHMR-AP, DON will establish organizational elements designed
to more effectively mitigate and respond to civilian harm. These include Civilian Environment Teams to assess civilian considerations for commanders; Civilian Harm Assessment
Cells to evaluate civilian harm resulting from operations; red-team personnel to support planning and reduce misidentification risks; and Civilian Harm Mitigation and Response
Officers positioned at combatant commands and across the joint force to ensure CHMR activities are fully integrated into command processes.

United States Forces Japan (USFJ)
Funding supports operations, activities, and actions conducted in Japan in support of U.S. Indo-Pacific Command (USINDOPACOM). USFJ executes current and future
operations, exercises, and training with alliance partners to maintain readiness and strengthen deterrence in Japan. USFJ manages the U.S.–Japan Alliance and serves as the focal
point for planning, coordination, and support of U.S. defense issues in Japan. Program increases support critical improvement projects at USFJ headquarters that enable the
ongoing expansion of USFJ and enhance its ability to maintain regional stability and security.

Asia Pacific Regional Initiative (APRI)
APRI provides theater-targeted funding for security cooperation activities aligned with the USINDOPACOM Commander's strategy. Enacted annually in the Appropriations Act,
APRI enables enhanced theater engagements, exercises, and activities that strengthen partnerships and advance U.S. objectives across the Indo-Pacific region.$$, NULL, NULL, $$O&M/FY27/Navy/OMN_Book.pdf$$, 267, 275, $$7c5f743d952a46c815286161365e3e6487f242c0d3569ffc152a140908e312ab$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_reserve_1c6c$$, 2027, $$Funding is provided for the readiness and peacetime support of combat support forces of Navy Expeditionary Combat Command (NECC), Navy Expeditionary Combat Forces
(NECF), Commander, Naval Surface Force Atlantic (CNSL), Navy Expeditionary Combat Command Pacific (NECCPAC), Commander, Naval Surface Force Pacific (CNSP), and
the operations of the Navy Reserve Force headquarters and its subordinate commands.

Navy Expeditionary Combat Command (NECC): NECC serves as a Type Command (TYCOM) for the Navy's expeditionary forces and as central management for the
readiness, resources, manning, training, and equipping of those forces to execute combat, combat support, and combat service support missions across the full spectrum of naval,
joint, and combined operations. These expeditionary Sailors support the U.S. Navy while serving as members of Maritime Expeditionary Groups, Naval Construction Groups,
Navy Expeditionary Logistics Support Group, and the Expeditionary Combat Readiness Center (ECRC). Funds provide for the logistic delivery system for the initial outfitting,
modernization, re-capitalization, and Integrated Logistic Support (ILS) for the Reserve Component of expeditionary forces.

Commander Naval Surface Atlantic (CNSL) / Commander, Naval Surface Pacific (CNSP): CNSL and CNSP are Type Commands (TYCOM) that provide combat ready
ships and stations to the fleet and ensures those ships and stations are supplied, equipped, maintained, and trained to conduct operations.

Commander Navy Reserve Forces (CNRF) Headquarters: Resources the operation of the Chief of Navy Reserve (Office of the Chief of Navy Reserve), Commander, Navy
Reserve Forces Command headquarters, and the Reserve Component of the Chief of Naval Operations (OPNAV) staff. These Commands provide policy, control, administration,
and management direction to include the management of all resources (manpower, hardware, and facilities) that maintain an optimum training posture and mobilization-ready
Navy Reserve Force. Funding also provides civilian salaries and administrative support. The OPNAV staff advises and assists the Chief of Naval Operations in the discharge of
his responsibilities as the principal advisor and executive of the Navy to the Secretary of the Navy on the conduct of the activities of the Department of the Navy, and as the Navy
member of the Joint Chiefs of Staff. The OPNAV Support Activity performs functions of an operational nature that support the Chief of Naval Operations Staff Offices.$$, NULL, NULL, $$O&M/FY27/Navy/OMNR_Book.pdf$$, 59, 69, $$e2f6cbb0b13332196be64d964dd10d050bca0a197cfe6e0c1072601a5cb1d129$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_reserve_4a4m$$, 2027, $$This sub-activity group funds maintenance and support for the following military manpower and personnel management systems: Navy Reserve Order Writing System (NROWS),
Reserve Headquarters Support (RHS) System, Reserve Integrated Management System (RIMS) Financial Management (FM), and Inactive Manpower and Personnel Management
Information System (IMAPMIS). Navy Personnel and Pay (NP2) is one of the cornerstones of the Navy/N1 Transformation strategy formerly known as Navy Standard Integrated
Personnel System (NSIPS). NP2 includes Navy Personnel and Pay sustainment and the collapse of Legacy Manpower Systems' functionality. NP2 is the Human Resources (HR)
component of Navy's Transformation Roadmap specifically focused on maximizing human capital and improving fleet readiness by ensuring the right skills are in the right place at
the right time. Also funded are all functions related to Reserve personnel management performed by the Navy Reserve Personnel Management Department (PERS-9).

Reserve Integrated Management System (RIMS): Reserve Integrated Management System (RIMS) Financial Management (FM) is a mission critical Financial Management
application created to manage those funds appropriated by Congress to the Navy Reserves. The system allows the entry and processing of two primary transactions reservations
and adjustments. The RIMS (FM) system handles information that is necessary for the conduct of day-to-day businesses, but does not materially affect support to deployed or
contingency forces in the short term.

Navy Reserve Order Writing System (NROWS): Navy Reserve Order Writing System (NROWS) is a consolidated information system that combines all Commander, Naval
Reserve Force (CNRF) order-writing functions. NROWS is a single, enterprise-wide application for putting a Reservist on Annual Training (AT), Active Duty Training (ADT),
and Inactive Duty Training Travel (IDTT) orders. It provides users and managers with information on total force readiness and availability for operational planning. The objective
of NROWS is to perform many of the data impact edits as early in the order writing process as possible. Meeting this objective reduces the number of applications and order
validations currently being performed manually and greatly decreases the application error rate.$$, NULL, NULL, $$O&M/FY27/Navy/OMNR_Book.pdf$$, 107, 114, $$b6af59ce6aabcd6e31ab4568e3d811cecee5613e3752e39e174b78f7cbb787c4$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_1ccy$$, 2026, $$Funding in this sub-activity supports all aspects of Cyberspace Activities specifically intended to secure, defend and preserve data, networks, net-centric capabilities, and other
designated systems by ensuring security controls and measures are in place, and taking internal defense actions. This includes access to system controls, monitoring,
administration and integration of cybersecurity into all aspects of engineering and acquisition of cyberspace capabilities. In addition, these activities include implementation,
evaluation, and dispose of information technology and services, as well as, information resources management, and the management, storage, transmission, and display of data and
information.

Administration (Civilian Salaries): Supports NAVWAR (BSO39) cyber programs.

Administration (Finance, Contracts and Management): Funding provides support to Information Assurance Management, specifically Command Information Systems Security
Management and Network Security Management. These systems keep NAVWAR Headquarters (HQ) and Program Executive Offices (PEOs) in compliance with assorted
Department of Defense (DoD) Cybersecurity directives.

Computer Network Defense (CND): CND provides operational maintenance support to fielded computer information assurance defense agents and primary network boundary
protection systems (to include Host Based Security Systems (HBSS) for IT-21 Ships and Outside Continental United States (OCONUS) Navy Enterprise Network (ONE-NET).
The funding also supports conducting shipboard CND operational readiness Computer Network Defense in Depth Baseline Assessments (CNDiDBA) and supports CND program
Information Assurance Vulnerability Management (IAVM). In addition, the funding provides for Commercial Off the Shelf (COTS) CND warranty support to operational system
components, maintenance of logistics support documentation, training curricula maintenance, and ISEA 24/7 Help Desk support. Funding also provides support for cyber
remediation initiatives within the Navy's CND program in order to achieve improved network defense and security wholeness. The funding also supports Navy Cyber Situational
Awareness (NCSA) Common Operational Picture (COP) and the Nuclear Command, Control, and Communications, Navy (NC3-N) system of systems. Funding will also be used
to support SHARKCAGE, providing mechanisms to sense cyber threats across all Navy shore and afloat networks to reduce the complexities of monitoring, assessing, and
detecting adversary activities across multiple enclaves. (e.g. Nonsecure Internet Protocol (IP) Router Network (NIPRNET), Secret Internet Protocol Router Network (SIPRNET),
Command, Control, Communications, Computers, & Intelligence (C4I), Combat Systems, Hull Mechanical & Electrical (HM&E), etc.)

Counter Insider Threat Capability (CITC): Executive Order 13587 and the National Insider Threat Policy mandate all United States Government departments and agencies to
implement insider threat programs that monitor user activity on all classified networks and provide an insider threat analytical and response capability. CITC is the Department of
the Navy's (DoN) implementation of this requirement. CITC's mission is to deter, detect, and respond to the threat from witting and unwitting insiders. The Personnel Risk
Indicator Detection Enterprise (PRIDE) is the materiel solution required to support the CITC mission, and it will consist of two parts: (1) User Activity Monitoring (UAM), which
will monitor user activity on Navy networks, and (2) an Integrated Tool Suite (ITS), which will provide the Information Technology platform for the analytic and response
capabilities. The PRIDE system will provide the technology required by the DoN Insider Threat Hub to comply with the National mandates and to protect Navy data, equipment,
and personnel from insider threats.

Cyber Mission Force (CMF): Operates in support of U.S. Cyber Command's (USCYBERCOM) mission to conduct and synchronize activities to secure, operate and defend DoD
information networks, attain freedom of action in cyberspace and, when directed, conduct full spectrum military cyberspace operations in order to enable actions in all domains,
ensure US/Allied freedom of action in cyberspace, and deny the same to our adversaries.

Cyber Security - Activities Support/Inspections: NAVIFOR HQ is the CYBER/C5ISR TYCOM responsible for Information Warfare (IW) Man, Train, Equipment (MT&E) to
include resource management, IW force generation and delivery to the Joint Force, IW doctrine, policy, and governance, training requirements, and community management. The$$, $$$$, NULL, $$O&M/FY26/Navy/OMN_Book.pdf$$, 320, 331, $$4a0a70524082df4657225b753e5529b9876aeacccea3220ba54dc286d3c02569$$, $$2026-05-10T00:20:58.246153+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_space_force_13z$$, 2027, $$The Base Support program provides funding for installation support functions, engineering and environmental programs in support of U.S. Space Force installations. The
program sustains mission capability, quality of life, workforce productivity and infrastructure support. Significant categories of support are listed below.

Unaccompanied Personnel Housing Services (UPH): Includes execution of government owned, leased, contracted, or privatized UPH. Functional categories include
unaccompanied personnel housing including permanent party UPH management services, initial issue of furnishings (furniture, appliances, and equipment) for newly
constructed and renovated facilities, and management of replacement furnishings (repair, replace, control, moving and handling, inventory, warehousing and disposal).

Airfield Operations:
Includes contracts, peculiar and support equipment, and associated costs specifically identified to plan, manage, coordinate, and execute airfield operations. This includes
weather, Air Traffic Control (ATC), terminal airspace management, airfield and flight management, RADAR, Air Traffic Control and Landing System (ATCALS) (including
off airfield navigational aids), communications systems maintenance, airfield equipment, transient services, liaison with installation movement for the provision of airfield
passenger and cargo terminals, and support to assigned, tenant, and transient U.S. military aircraft and aircrew.

Command Support:
Includes contracts, peculiar and support equipment, and associated costs specifically identified and measurable to plan, manage, coordinate, and execute command
support functions such as Command Management (CM), installation Public Affairs (PA), Legal Support (LS), Financial Management (FM), Management Analysis (MA),
procurement operations, installation safety, installation chaplain ministries, and installation history and museums. CM includes postal services, honors/protocol, advisory
services, administration, executive office, and inspector general/internal review. PA includes distribution of internal information (e.g., base newspapers, military radio/TV
stations); public information (e.g., press releases, media training/outreach), website content management. LS includes military justice, installation operations,
administrative, international, business law, claims. FM includes program/budget analysis/development, financial advisory services, budget execution support, accounting
liaison services. MA includes strategic planning, requirements development, performance management systems, and organizational structure analysis. Procurement
operations includes purchasing, leasing, obtaining supplies, services, non-military construction; contract operations, and government purchase card management.
Installation safety includes training, evaluations/consultations; mishaps, near misses/complaint investigations; airfield, industrial, off-duty recreational, range, explosives,
and traffic safety awareness programs. Chaplain ministries includes worship services, chaplaincy education/training, advice to the commander, and counseling. History
and museums includes maintaining an accurate record of installation activities in peace/war, and management of museums/historical artifacts.

Installation Law Enforcement Operations:
Includes contracts, peculiar and support equipment, and associated costs specifically identified and measurable to plan, manage, coordinate, and execute functions of
installation Law Enforcement (LE) operations and physical security. Installation LE Operations includes enforcing federal, state and military law, enforcing installation
guidance, issuance of citations, detaining suspects, motor vehicle traffic management, traffic investigations, apprehension and restraint of offenders, crowd control, crime
prevention, crime detection, LE patrols, LE liaison, apprehension of persons who commit crimes on the installation, testifying in prosecution cases and temporary detention
of offenders. This includes protecting, defending, and deterring against criminal activities, conduct of minor investigations, the development of plans for the employment of
law enforcement personnel, emergency response, and management as it relates to law enforcement activities and functions and which includes all processes intended to
preserve the principles of law through various strategies. Physical security includes roaming security patrols, entry control, electronic security system installation,

monitoring, and maintenance, physical barriers such as fencing, bollards, drop arms and gates to protect the installation, technology integration of positive control
measures, badging systems, surveillance and demarcation of controlled and restricted areas.

Facilities Operations:
This program provides engineering operations, engineering services, and real property management required to accomplish municipal-type activities. These activities
include emergency services (fire protection and aircraft crash rescue), utility plant operations, refuse collection and disposal (including non-hazardous recycling), custodial
services, snow removal, street sweeping, grounds maintenance, and insect control. The program also funds real property leases and purchased utilities (electric, gas,
water and sewer).$$, $$$$, NULL, $$O&M/FY27/Air Force/FY27 Space Force Operation & Maintenance Volume I.pdf$$, 164, 166, $$4bbb04c49c1b4b6d34a4f38b7c804f7951d8f55aff61620561b66b0a617e8526$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_3a2j$$, 2027, $$Recruit Training indoctrinates recruits in basic military principles and naval skills, and provides a realistic understanding of fleet environment and shipboard life. The Recruit
Training Program accomplishes its purpose through integration of men and women into a structured environment that stresses order, discipline, teamwork, responsive behavior,
loyalty, and pride in service. Resources support costs associated with recruit in-processing; training devices; training device support and maintenance; indoor fitness/drill facilities;
classroom facilities, equipment, and supplies; administrative staff salaries, supplies, travel; and other training and equipment. The Recruit Training syllabus is structured to provide
the required training to meet the programs' objective in a minimum amount of time, which is 73 curriculum days.

In addition to new recruits entering active duty, Basic Military Training (BMT) is provided to Selected Reservists in the Navy Reserve Enlisted under the Full-Time Support (FTS)
and Navy Accession Training (NAT) programs. Orientation and training is also provided to Navy Veterans and Other Service Veterans (NAVET/OSVET) re-entering the Naval
Service.

The Future Sailor Preparatory Course (FSPC) is an innovative program to help young men and women who want to serve in the Navy but cannot pass physical or academic
requirements. This program consists of two tracks – fitness and academic. The fitness track is for potential recruits who do not meet the Navy's enlistment body fat composition
standards. The academic track is for potential recruits who cannot attain a passing score on the Armed Services Vocational Aptitude Battery test. The program provides three
weeks of individualized paid training to potential recruits to improve their shortcomings so they can join the Navy. Upon completion, successful recruits are able to attend regular
boot camp training.

Battle Stations 21 is the capstone-training event at Recruit Training Command (RTC) Great Lakes. This training event is used to test recruits in a simulated combat environment to
help build Sailor confidence under stress. Battle Stations 21 is housed in a single facility and brings multiple stand-alone scenarios into a single storyline composed of realistically
sequenced events experienced onboard a simulated ship. It serves as the "rite of passage" from recruit to Sailor.$$, NULL, NULL, $$O&M/FY27/Navy/OMN_Book.pdf$$, 455, 462, $$465bf671e377c69e676b308e128f20212d5aa03d6dfbae085c43fecc7cd3e046$$, $$2026-05-09T23:43:48.682814+00:00$$) ON CONFLICT DO NOTHING;
