INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_comp_1$$, 2026, $$This Budget Activity Group provides for the delivery of medical and dental care plus pharmaceuticals received by Department of War (DoW) eligible beneficiaries
in Military Treatment Facilities and Dental Treatment Facilities in the Continental United States (CONUS) and Outside the Continental United States (OCONUS).
This program includes the following:

Care in Department of War Medical Centers, Hospitals and Clinics - Includes resources for providing healthcare in DoW-owned and operated CONUS and
OCONUS Military Treatment Facilities which are staffed and equipped to provide inpatient care for both surgical and medical patients and/or outpatient care for
ambulatory patients.

Dental Care - Includes resources for providing dental care and services in CONUS and OCONUS to authorized personnel through hospital departments of
dentistry, installation dental clinics, and Regional Dental Activities.

Pharmaceuticals - Includes all pharmaceuticals, pharmacy manpower authorizations, support equipment, and other costs directly associated with the production
and operation of Pharmacy Services in DoW owned and operated CONUS and OCONUS facilities.$$, NULL, NULL, $$Budget J-Books/FY27/MHS/MHS_PB27_J-Book-Vol1-COMP_PSCP.pdf$$, 35, 36, $$62fe7a96f862d4aa6ca7c28fb0e2e8f5d080234d4f7a011790601879ca17d656$$, $$2026-05-09T21:43:13.101023+00:00$$) ON CONFLICT DO NOTHING;
