INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_comp_7759$$, 2026, $$The Defense Health Agency (DHA) Local Area Network (LAN) and Wireless LAN (WLAN) technology refresh program ensures mission assurance for the Military
Health System (MHS) across all Military Treatment Facilities (MTFs). The program directly mitigates unacceptable operational risk by replacing end-of-support
(EOS) network infrastructure that is non-compliant with Department of War (DoW) cybersecurity mandates, including Security Technical Implementation Guides
(STIGs). Failure to execute this lifecycle replacement results in critical vulnerabilities (CAT1/CAT2 findings) that would compel an operational shutdown of the
networks to maintain information assurance. Such a directed shutdown would suspend all MHS data communications, disabling access to mission-critical systems,
including MHS GENESIS, thereby compromising patient safety and degrading the delivery of the healthcare benefit. This investment provides the requisite
infrastructure baseline to guarantee continuity of operations and support the strategic modernization of MHS information systems.

                                                                                                                                                   P-40 Exhibit
                                                                                                                                                        COMP$$, NULL, NULL, $$Budget J-Books/FY27/MHS/MHS_PB27_J-Book-Vol1-COMP_PSCP.pdf$$, 180, 180, $$588f434666441dd3518ff003cac67620c0c8ead33223f76b56ddb245b900c7ba$$, $$2026-05-09T21:43:13.101023+00:00$$) ON CONFLICT DO NOTHING;
