INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_comp_7721$$, 2026, $$To fortify the readiness and optimize the health outcomes of our warfighters and beneficiaries, DHA prioritizes strategic investments in cutting-edge medical
devices and equipment. These investments are critical enablers for maintaining a technologically advanced and resilient military healthcare system capable of
delivering exceptional care in both garrison and deployed environments. To maximize impact on patient care, support to the combatant commands, operational
effectiveness, and long-term cost containment, DHA's most significant medical equipment investments will be to focus on radiological capabilities, surgical
excellence, pathology and laboratory efficiency, Food and Drug Administration (FDA) and non-FDA medical products and devices, and information systems
functional areas.

Equipping our medical personnel with advanced imaging modalities, including MRI, CT, X-ray, Ultrasound, and Echocardiography, provides the critical diagnostic
advantage needed to rapidly assess and treat injuries and illnesses. Furthermore, investing in state-of-the-art surgical equipment, encompassing advanced
operating room tools and surgical robotics, enhances precision, reduces invasiveness, and accelerates recovery times. As a result, our MHS skilled professionals
can fully leverage these technologies for optimal patient outcomes, essential to our readiness to support the warfighter both on the battlefield and at home. These
strategic investments strengthen our commitment to readiness, optimize patient outcomes, and safeguard the health and well-being of those who serve and their
families. Investing in modernization improves our ability to ensure medical readiness and the health of our force.

                                                                                                                                                       P-40 Exhibit
                                                                                                                                                            COMP$$, NULL, NULL, $$Budget J-Books/FY27/MHS/MHS_PB27_J-Book-Vol1-COMP_PSCP.pdf$$, 177, 177, $$38e4fcb163aef063638668b7b320b263211eae159302caad7e5ed258584cdbc7$$, $$2026-05-09T21:45:29.619604+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_comp_7721$$, 2027, $$To fortify the readiness and optimize the health outcomes of our warfighters and beneficiaries, DHA prioritizes strategic investments in cutting-edge medical
devices and equipment. These investments are critical enablers for maintaining a technologically advanced and resilient military healthcare system capable of
delivering exceptional care in both garrison and deployed environments. To maximize impact on patient care, support to the combatant commands, operational
effectiveness, and long-term cost containment, DHA's most significant medical equipment investments will be to focus on radiological capabilities, surgical
excellence, pathology and laboratory efficiency, Food and Drug Administration (FDA) and non-FDA medical products and devices, and information systems
functional areas.

Equipping our medical personnel with advanced imaging modalities, including MRI, CT, X-ray, Ultrasound, and Echocardiography, provides the critical diagnostic
advantage needed to rapidly assess and treat injuries and illnesses. Furthermore, investing in state-of-the-art surgical equipment, encompassing advanced
operating room tools and surgical robotics, enhances precision, reduces invasiveness, and accelerates recovery times. As a result, our MHS skilled professionals
can fully leverage these technologies for optimal patient outcomes, essential to our readiness to support the warfighter both on the battlefield and at home. These
strategic investments strengthen our commitment to readiness, optimize patient outcomes, and safeguard the health and well-being of those who serve and their
families. Investing in modernization improves our ability to ensure medical readiness and the health of our force.

                                                                                                                                                       P-40 Exhibit
                                                                                                                                                            COMP$$, NULL, NULL, $$Budget J-Books/FY27/MHS/MHS_PB27_J-Book-Vol1-COMP_PSCP.pdf$$, 177, 177, $$38e4fcb163aef063638668b7b320b263211eae159302caad7e5ed258584cdbc7$$, $$2026-05-09T21:45:29.619604+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_comp_7746$$, 2026, $$The purpose of JOMIS is to modernize, deploy, and sustain the DoW's OpMed Information System (IS) capabilities that enable comprehensive health services to
meet Warfighter requirements for military medical operations. JOMIS is intended to function in constrained, intermittent, and non-existent communications
environments while providing access to authoritative sources of clinical data. Current challenges in the OpMed mission include aged technology, inefficient design
standards, overreliance on obsolete code, lack of automation, different deployment methods across the services that impact standard user adoption, inefficient
acquisition methods, and the lack of unified functional user input.

To mitigate these challenges, JOMIS has planned the following actions:
• Translate the Theater Medical Information Requirements (TMIR) IS Capability Development Document into a modern Portfolio Capability Roadmap that can be
abstracted down to needs statements, personas, and user stories that can inform leading-edge design practices.
• Construct program governance that can be achieved through external consultancy and resource investment into an Operational Medicine Functional Champion
to create a high achieving team that envisions the future of OpMed capabilities as they are integrated with DoW and Federal medical data landscapes.
• Leverage experiential learning on current innovative projects that provide ample opportunities to explore modern software delivery methods that can create and
endure software delivery environments that evolve with the OpMed mission.
• Take advantage of industry and DoW best practices to evolve and perfect development methods (e.g., Agile and Development Security Operations) which will
facilitate the ability to "continuously integrate" and "continuously deliver" capability throughout the software development life cycle.

                                                                                                                                                     P-40 Exhibit
                                                                                                                                                          COMP$$, NULL, NULL, $$Budget J-Books/FY27/MHS/MHS_PB27_J-Book-Vol1-COMP_PSCP.pdf$$, 179, 179, $$c06022b1cf4564ec9ee63c53505dcc3275a24920bcae38c46e70c04d2097ee2a$$, $$2026-05-09T21:45:29.619604+00:00$$) ON CONFLICT DO NOTHING;
