INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_af_active_31d$$, 2026, $$Air Force Reserve Officer Training Corps (AFROTC) is the largest source of new officer accessions for the Air Force and the primary source of commissioning for technical
Air Force Specialty Codes. The AFROTC mission is to develop quality leaders for the Air Force. The mission is primarily achieved through funding college scholarship
tuition, textbooks and summer training programs. The AFROTC program is designed to recruit, educate, train, motivate, and commission officer candidates through a
comprehensive college program.$$, NULL, NULL, $$O&M/FY26/Air Force/FY26 Air Force Operations and Maintenance Vol I.pdf$$, 449, 450, $$0f7c122f629cb4cbda88e448c646e549fe113a0a145fc02262f05fb5fdce375d$$, $$2026-05-10T00:20:58.246153+00:00$$) ON CONFLICT DO NOTHING;
