INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_comp_4$$, 2026, $$Service Medical Information Management/Information Technology (IM/IT) – Provides resources for Military Treatment Facility (MTF) IM/IT activities,
infrastructure, Service Medical specific systems; and Functional Area Applications (Service-Unique); Communications and Computing Infrastructure to include
Information Assurance, long haul/wide area and deployable tactical/shipboard communications, office automation, and video-teleconferencing; and related
technical activities including information architecture, data standardization, and data interoperability. Expressly excludes Base Communications and Voice
Communications requirements funded in the Base Operations/ Communications Budget Activity Group.

Military Health System (MHS) Information Management/Information Technology Support Programs – Provides resources for services contracted or
provided by other Department of War (DoW) agencies. Includes modifications to contractor-owned IM/IT systems to meet congressional and other mandated
changes; changes or modifications to other DoW agencies' IM/IT systems to comply with changes in medical regulatory guidance; commercially purchased IM/IT-
related services to support the Managed Care Support Contracts' compliance requirements; and funding to support centrally managed office automation, video-
teleconferencing and related technical activities including information architecture, data standardization and data interoperability. Expressly excludes funding for
