INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_ctra_umbrella$$, 2026, $$This sub-activity group (CTRA, Cooperative Threat Reduction Account) had FY26 estimate of $0 — line item not funded in FY26. Per the FY27 PB O-1 Summary, this program received funding only beginning FY27. The dedicated FY26 J-Book is not included in the current corpus; if needed for FY26 narrative, source from FY26 PB special-fund books (currently pending owner upload). FY27 narrative is published in the corresponding J-Book and ingested separately. Source: FY27 PB O-1 Summary line for CTRA. synth_special_fund_fy26_zero v41.$$, NULL, NULL, $$O&M/FY27/FY2027_o1.pdf$$, NULL, NULL, $$ff013f3851afe81f45e99acb04ff5238434a469d0622b698e371b38f6779c35c$$, $$2026-05-10T01:03:08.635372+00:00$$) ON CONFLICT DO NOTHING;
