INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_af_reserve_42k$$, 2027, $$Funding supports the Air Reserve Personnel Center (ARPC), which enhances warfighting readiness for the total force by delivering personnel services to airmen from
initial entry to retirement and providing direct support to wing-level force support and commander support staffs, ensuring the execution of Headquarters Air Force and
Department of War policy. Operations financed include full-time manpower and other resources required to provide a wide variety of services including accessions,
assignments, force development, mobilization, Individual Ready Reserve (IRR) classification and training, entitlements, service verification, evaluation, points
management, retirements, separation, education, casualty, promotions and policies and procedures, and board operations. The ARPC serves as a central hub for many
critical personnel functions that support the readiness and well-being of airmen throughout their careers.

                                                                Activity Group: Servicewide Activities
