INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_reserve_1a1a$$, 2026, $$The Operating Forces budget line item supports the day-to-day costs to train and support the Marine Forces Reserve (MFR). Programs within this line item include funding for
materiel readiness, purchase and replacement of expense type items authorized by unit training allowances, local repair of equipment, training centers, and embarkation materials
for training and preparation for mobilization. Operating Forces provide funding for annual exercise training in preparation for deployments such as Desert Fire Exercises (CAXs),
the Weapons and Tactics Instructor Course (WTI), Mountain Warfare training (MTX), and Arctic Weather training. It also provides resources for equipment and ammunition
shipments, essential travel, contract billeting, Maintenance Contact Teams (MCT), inspections, travel, recurring services such as Reserve Health Assessments, Contractor
Engineering Technical Services (CETS), equipment calibration, Global Command & Control System (GCCS) technicians, consumables, reproduction, and equipment
replacement/replenishment.$$, NULL, NULL, $$O&M/FY26/Navy/OMMCR_Book.pdf$$, 19, 27, $$a4b3559a9e3cf03486b808adc2f6ff8e07d0503f4ad2162d8623ebbaf2787fb2$$, $$2026-05-10T00:20:58.246153+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_reserve_1a3a$$, 2026, $$This sub-activity group finances the depot maintenance (major repair/rebuild) of Marine Forces Reserve ground equipment. Depot Maintenance programs fund the overhaul,
repair, and maintenance of automotive equipment, combat vehicles, construction equipment, electronics and communications systems, general purpose equipment, missiles, and
ordnance/weapons/munitions performed at both public (DoD) and private (contractor) facilities. Repair and rebuild are accomplished on a coordinated schedule to help manage
and maintain the materiel readiness of the equipment inventory necessary to support the operational needs of the Marine Corps. Items programmed for repair are screened to
ensure that a valid stock requirement exists and that the repair or rebuild of the equipment is the most cost effective means of satisfying the requirement. This program is closely
coordinated with the Procurement, Marine Corps appropriation to ensure that the combined repair and procurement program provides a balanced level of attainment and
maintenance of inventory objectives for major equipment. The specified items are updated annually based on current applicable cost factors at the performing activities.$$, NULL, NULL, $$O&M/FY26/Navy/OMMCR_Book.pdf$$, 28, 34, $$91f1866d165188d9ddb78a1e794a519f6de92fc30208788820315ab640cb791c$$, $$2026-05-10T00:20:58.246153+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_reserve_bsm1$$, 2026, $$This subactivity group funds Facilities Sustainment, Restoration, and Modernization (FSRM) for the Marine Forces Reserve. Sustainment provides resources for maintenance and
repair activities necessary to keep an inventory of facilities in good working order. It includes regularly scheduled assessments and inspections, preventive maintenance tasks, and
emergency response and service calls for minor repairs. Sustainment also includes major repairs or replacement of facility components (usually accomplished by contract) that
occur periodically throughout the life cycle of facilities. This work includes regular roof replacement, refinishing of wall surfaces, repair and replacement of heating and cooling
systems, replacement of tile and carpeting, and similar work. Restoration includes repair and replacement work to restore facilities damaged by excessive age, natural disaster,
fire, accident, inadequate sustainment, or other causes. Modernization includes facility alteration solely to implement new or higher standards (including regulatory changes), to
accommodate new functions, or to replace building components that typically last more than 50 years (such as framework or foundations). Funding supports assessments that
identify and prioritize energy (including water) reduction opportunities and implement energy conservation measures to improve efficiency and reduce costs associated with the
use of electricity, natural gas, heating fuels, and potable water necessary to operate Marine Corps Reserves facilities.$$, NULL, NULL, $$O&M/FY26/Navy/OMMCR_Book.pdf$$, 35, 41, $$e66c944fdb3d5eeb6fb90999f3928557becec2a83574bb61f7a1d02abf0452c0$$, $$2026-05-10T00:20:58.246153+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_4s53$$, 2026, $$Sub-program of 4B2N (Planning, Engineering, and Program). FY2026 estimate: $0. This sub-activity group (4S53, DON TRR (Ashore)) appears as a line item within the parent SAG's O-1 Summary table — see OMMC_Book.pdf line 468: "1106N   230   4S53 DON TRR (Ashore)                        U             1,638". Per the parent SAG's OP-5 narrative, sub-program rollups of this kind do not receive standalone descriptions; refer to the parent SAG (4B2N) narrative for context. Source: O&M/FY26/Navy/OMMC_Book.pdf line 468 (line-item citation) + parent SAG 4B2N narrative. synth_subprogram v41.$$, NULL, NULL, $$O&M/FY26/Navy/OMMC_Book.pdf$$, 468, 468, $$3db593dbce6576a943c7e7459402f94cb0e6e162cacc8319b706140909d8a19e$$, $$2026-05-10T01:03:08.635372+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_mc_active_4s54$$, 2026, $$Sub-program of 4B2N (Planning, Engineering, and Program). FY2026 estimate: $0. This sub-activity group (4S54, DoN TRR 3 Transition Support) appears as a line item within the parent SAG's O-1 Summary table — see OMMC_Book.pdf line 487: "1106N   240   4S54 DoN TRR 3 Transition Support               U            1,310". Per the parent SAG's OP-5 narrative, sub-program rollups of this kind do not receive standalone descriptions; refer to the parent SAG (4B2N) narrative for context. Source: O&M/FY26/Navy/OMMC_Book.pdf line 487 (line-item citation) + parent SAG 4B2N narrative. synth_subprogram v41.$$, NULL, NULL, $$O&M/FY26/Navy/OMMC_Book.pdf$$, 487, 487, $$f9a26f40d5deb602b568c725196a7cfe6fea5dd51d2f565048a42acd8e39b9ea$$, $$2026-05-10T01:03:08.635372+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_af_ng_11g$$, 2027, $$Air National Guard (11G, Mission Support Operations). FY 2027 PB request: $663.4M. FY26 → FY27: $627.7M → $663.4M (+$35.7M, +5.7%).

NOTE ON SOURCE: The FY 2027 Air National Guard Operation & Maintenance Volume I OP-5 publication (saffm.hq.af.mil/Portals/84/documents/FY27/ANG OM FY27PB FINAL Volume I.pdf) is access-restricted in the public corpus. The FY 2027 program-mission scope for this SAG is inferred to be substantively consistent with the FY 2026 ANG Vol I OP-5 narrative (reproduced below), with funding adjustments per the FY 2027 O-1 Summary line for 11G. The full FY 2027 narrative will be ingested if/when the source PDF becomes available.

--- FY 2026 ANG Vol I OP-5 Narrative for 11G (Mission Support Operations) — source: O&M/FY26/Air Force/FY26 Air National Guard Operation and Maintenance Vol I.pdf page 56 ---

This subactivity group includes funds for mission support operations to include payroll for Dual Status Military Technicians who carry on the day-to-day training,
maintenance, and administration of the Air National Guard (ANG). Funding includes transportation and per diem cost; communications services; vehicles; equipment and
supplies. Funds all costs related to operation of mission support functions such as the 1st Air Force, Command/Control, Civil Engineering, Air Traffic Control, and Combat
Communications. It also includes funding for field training, exercises and maneuvers, training equipment, and supplies.$$, NULL, NULL, $$O&M/FY27/Air Force/FY27 Air National Guard Operation & Maintenance Volume II.pdf$$, NULL, NULL, $$cc95bdf29f2bbde234e60dd52a365077b0c6c21398cc5f6275abcb1f9fa7fa94$$, $$2026-05-10T01:36:00.276483+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_af_ng_11m$$, 2027, $$Air National Guard (11M, Depot Purchase Equipment Maintenance). FY 2027 PB request: $1210.5M. FY26 → FY27: $1068.1M → $1210.5M (+$142.3M, +13.3%).

NOTE ON SOURCE: The FY 2027 Air National Guard Operation & Maintenance Volume I OP-5 publication (saffm.hq.af.mil/Portals/84/documents/FY27/ANG OM FY27PB FINAL Volume I.pdf) is access-restricted in the public corpus. The FY 2027 program-mission scope for this SAG is inferred to be substantively consistent with the FY 2026 ANG Vol I OP-5 narrative (reproduced below), with funding adjustments per the FY 2027 O-1 Summary line for 11M. The full FY 2027 narrative will be ingested if/when the source PDF becomes available.

--- FY 2026 ANG Vol I OP-5 Narrative for 11M (Depot Purchase Equipment Maintenance) — source: O&M/FY26/Air Force/FY26 Air National Guard Operation and Maintenance Vol I.pdf page 73 ---

This subactivity group provides funds for depot level maintenance and repair performed on aircraft, engines, vehicles, and other major items of equipment. Includes all
work associated with the repair, corrosion control, reclamation, assembly and disassembly, inspection testing and supplies and equipment procured to support the
maintenance of Air National Guard (ANG) assets. Depot maintenance is required to repair, overhaul and upgrade ANG weapon systems and equipment to enable the ANG
to be capable of conducting independent operations in accordance with wartime taskings. This estimate provides funds for depot maintenance, including corrective
maintenance of aircraft, equipment accessories, and electronic communications equipment.$$, NULL, NULL, $$O&M/FY27/Air Force/FY27 Air National Guard Operation & Maintenance Volume II.pdf$$, NULL, NULL, $$3a3b574d9f63a3ca0257afa380afe9147c4071d426589f9290ee80e98c0d80d5$$, $$2026-05-10T01:36:00.276483+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_af_ng_11r$$, 2027, $$Air National Guard (11R, Facilities Sustainment, Restoration &). FY 2027 PB request: $531.2M. FY26 → FY27: $576.6M → $531.2M ($-45.3M, -7.9%).

NOTE ON SOURCE: The FY 2027 Air National Guard Operation & Maintenance Volume I OP-5 publication (saffm.hq.af.mil/Portals/84/documents/FY27/ANG OM FY27PB FINAL Volume I.pdf) is access-restricted in the public corpus. The FY 2027 program-mission scope for this SAG is inferred to be substantively consistent with the FY 2026 ANG Vol I OP-5 narrative (reproduced below), with funding adjustments per the FY 2027 O-1 Summary line for 11R. The full FY 2027 narrative will be ingested if/when the source PDF becomes available.

--- FY 2026 ANG Vol I OP-5 Narrative for 11R (Facilities Sustainment, Restoration &) — source: O&M/FY26/Air Force/FY26 Air National Guard Operation and Maintenance Vol I.pdf page 86 ---

Facilities Sustainment and Restoration/Modernization (FSRM) functions include facility and infrastructure sustainment, restoration, modernization and demolition activities.
FSRM activities ensure installation facilities; utility systems and infrastructure are capable of fully supporting mission requirements. This Subactivity Group provides FSRM
and demolition support for Air National Guard (ANG) installations and includes funding for the repair, maintenance of facilities, and construction of buildings, roads, and
airfields required for the training of ANG personnel.$$, NULL, NULL, $$O&M/FY27/Air Force/FY27 Air National Guard Operation & Maintenance Volume II.pdf$$, NULL, NULL, $$81366698d7741847a184869e8d441cdab6896e6a30bf31d2dbde99f271a2ecc7$$, $$2026-05-10T01:36:00.276483+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_af_ng_11v$$, 2027, $$Air National Guard (11V, Cyberspace Sustainment). FY 2027 PB request: $26.4M. FY26 → FY27: $16.1M → $26.4M (+$10.2M, +63.3%).

NOTE ON SOURCE: The FY 2027 Air National Guard Operation & Maintenance Volume I OP-5 publication (saffm.hq.af.mil/Portals/84/documents/FY27/ANG OM FY27PB FINAL Volume I.pdf) is access-restricted in the public corpus. The FY 2027 program-mission scope for this SAG is inferred to be substantively consistent with the FY 2026 ANG Vol I OP-5 narrative (reproduced below), with funding adjustments per the FY 2027 O-1 Summary line for 11V. The full FY 2027 narrative will be ingested if/when the source PDF becomes available.

--- FY 2026 ANG Vol I OP-5 Narrative for 11V (Cyberspace Sustainment) — source: O&M/FY26/Air Force/FY26 Air National Guard Operation and Maintenance Vol I.pdf page 97 ---

Provides funds for Cyber Contractor Logistics Support to include Depot level maintenance. The Air Force enhances the management and programming by reviewing the
total force sustainment requirements at the enterprise level. Weapon System Sustainment (WSS) includes Depot Purchase Equipment Maintenance (DPEM) and
Contractor Logistics Support (CLS).$$, NULL, NULL, $$O&M/FY27/Air Force/FY27 Air National Guard Operation & Maintenance Volume II.pdf$$, NULL, NULL, $$1e11b7a0f4f3054f827b0faf3fa2ade9209e1fcc7e1f48d35b4ff56d7159730e$$, $$2026-05-10T01:36:00.276483+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.om_sag_narratives (sag_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$om_navy_active_1a4a$$, 2027, $$This sub-activity group (1A4A — Air Operations and Safety Support) was discontinued in the FY 2027 President's Budget. It does NOT appear as a standalone OP-5 narrative section in the FY 2027 Navy (active) O&M Volume I book (verified: zero `Exhibit OP-5, Subactivity Group 1A4A` footer occurrences). See the FY 2027 O-1 Summary at page 21 for the active subactivity group set.

Funding history (in $K):
  FY 2024 enacted: $215,873K  ·  FY 2025 current: $0K  ·  FY 2026 estimate: $0K  ·  FY 2027 PB request: $0 (no line).

The 1A4A scope (Air Operations and Safety Support — Expeditionary Airfields, Aviation Facilities and Landing Aids, Aviation Mobile Facilities, Aviation Life Support Systems, Air Traffic Control, MATCALS, Aircraft Launch and Recovery Equipment, Aviation Foreign Object Damage Mitigation) is consolidated into the 1A4N subactivity ('Air Systems Support') beginning in FY 2026. The FY 2027 OMN_Book at page 68 (1A4N OP-5 narrative, 'Detail by Subactivity Group: Air Systems Support') explicitly carries the prior 1A4A program descriptions as a sub-section under the title 'Air Operations and Safety Support'. The funding rollup table inside 1A4N (line 2951 of the .txt) shows 'Air Operations and Safety Support Total: 201,866 / 16,254 / 16,357' (FY25/FY26/FY27 in $K), indicating the historical $215.873M FY24 baseline was reduced to ~$16.357M FY27 as part of the consolidation (≈92% efficiency reduction).$$, $$$$, NULL, $$O&M/FY27/Navy/OMN_Book.pdf$$, 21, 21, $$v190_patched_2026-05-09_1a4a_title_fix$$, $$2026-05-10T00:12:17.530869+00:00$$) ON CONFLICT DO NOTHING;
